/**
 * P4.2 — Public glossary: 200+ FX / Moroccan regulatory / banking terms.
 * Each term has a slug, a short definition (FR + EN), and a category.
 * Used for SEO long-tail traffic and internal linking from blog posts.
 */

export type GlossaryCategory =
  | 'fx-basics'
  | 'fx-advanced'
  | 'mad-specific'
  | 'regulation-oc'
  | 'risk-management'
  | 'banking-morocco'
  | 'monetary-policy'
  | 'instruments';

export interface GlossaryTerm {
  slug: string;
  term: string;
  shortFr: string;
  shortEn: string;
  longFr: string;
  longEn: string;
  category: GlossaryCategory;
  related: string[]; // slugs
  examples?: string[];
}

export const GLOSSARY_CATEGORIES: Record<GlossaryCategory, { label: string; icon: string }> = {
  'fx-basics':         { label: 'Notions FX de base',      icon: '📚' },
  'fx-advanced':       { label: 'FX avancé',                icon: '🎓' },
  'mad-specific':      { label: 'Spécifique au MAD',       icon: '🇲🇦' },
  'regulation-oc':     { label: 'Réglementation OC',        icon: '⚖️' },
  'risk-management':   { label: 'Gestion des risques',     icon: '🛡️' },
  'banking-morocco':   { label: 'Banque au Maroc',         icon: '🏦' },
  'monetary-policy':   { label: 'Politique monétaire',     icon: '🏛️' },
  'instruments':       { label: 'Instruments financiers',  icon: '💱' },
};

export const GLOSSARY: GlossaryTerm[] = [
  // === FX BASICS ===
  { slug: 'taux-de-change', term: 'Taux de change', shortFr: 'Prix d\'une devise exprimée dans une autre devise.', shortEn: 'Price of one currency expressed in another.', longFr: 'Le taux de change est le prix relatif de deux devises. Il détermine combien d\'unités d\'une devise (la devise de contrepartie) sont nécessaires pour acheter une unité de l\'autre devise (la devise de base). Le MAD est la devise de base pour le dirham marocain.', longEn: 'An exchange rate is the relative price of two currencies. It determines how many units of one currency (the quote currency) are needed to buy one unit of the other (the base currency). The MAD is the base currency for the Moroccan dirham.', category: 'fx-basics', related: ['pip', 'cross-rate'], examples: ['EUR/MAD = 10.85 signifie qu\'1 EUR = 10.85 MAD'] },
  { slug: 'pip', term: 'Pip', shortFr: 'Plus petite variation standard d\'un taux de change (0.0001).', shortEn: 'Smallest standard change in an exchange rate (0.0001).', longFr: 'Un pip est la 4ème décimale d\'un taux de change (0.0001). Pour les paires JPY, 1 pip = 0.01. Pips sont utilisés pour mesurer les mouvements de prix et calculer les gains/pertes.', longEn: 'A pip is the 4th decimal of a quoted exchange rate (0.0001). For JPY pairs, 1 pip = 0.01. Pips measure price movements and P&L.', category: 'fx-basics', related: ['taux-de-change', 'forward-points'], examples: ['EUR/USD passant de 1.0850 à 1.0851 = +1 pip'] },
  { slug: 'cross-rate', term: 'Cross rate / Taux croisé', shortFr: 'Taux entre deux devises calculé via une devise pivot (souvent USD).', shortEn: 'Rate between two currencies calculated via a pivot (often USD).', longFr: 'Un cross rate est un taux de change entre deux devises qui ne contient pas le dollar US. Exemple : EUR/JPY, GBP/CHF. Il est calculé à partir des taux par rapport à l\'USD.', longEn: 'A cross rate is an exchange rate between two currencies that does not include the USD. Example: EUR/JPY, GBP/CHF. It is derived from rates against USD.', category: 'fx-basics', related: ['taux-de-change', 'pip'] },
  { slug: 'bid-ask', term: 'Bid / Ask', shortFr: 'Bid = prix d\'achat, Ask = prix de vente. Spread = Ask − Bid.', shortEn: 'Bid = buy price, Ask = sell price. Spread = Ask − Bid.', longFr: 'Le bid est le prix auquel le marché (ou votre banque) achète la devise de base. L\'ask est le prix auquel il la vend. Le spread est la rémunération du teneur de marché.', longEn: 'The bid is the price at which the market (or your bank) buys the base currency. The ask is the price at which it sells. The spread is the market-maker\'s compensation.', category: 'fx-basics', related: ['pip', 'spread'], examples: ['EUR/MAD bid=10.84, ask=10.86 → spread = 2 pips = 0.18%'] },
  { slug: 'spread', term: 'Spread', shortFr: 'Écart entre prix bid et ask, exprimé en pips ou %.', shortEn: 'Difference between bid and ask, in pips or %.', longFr: 'Le spread est l\'écart bid-ask. Il représente le coût de transaction implicite. Plus le spread est serré, plus le marché est liquide.', longEn: 'The spread is the bid-ask difference. It is the implicit transaction cost. Tighter spread = more liquid market.', category: 'fx-basics', related: ['bid-ask', 'pip'], examples: ['EUR/MAD billet 200-220 pips vs virement 10-15 pips'] },
  { slug: 'spot', term: 'Spot', shortFr: 'Transaction au cours du jour, livraison T+2 standard.', shortEn: 'Transaction at current rate, T+2 standard delivery.', longFr: 'Le spot est la transaction de change au cours du jour, avec livraison standard T+2 (2 jours ouvrés). Pour le MAD, c\'est la référence quotidienne publiée par Bank Al-Maghrib à 12h30 (intraday) et 16h15 (clôture).', longEn: 'A spot is a foreign exchange transaction at the current rate, with T+2 standard delivery (2 business days). For MAD, the daily reference is published by Bank Al-Maghrib at 12:30 (intraday) and 16:15 (close).', category: 'fx-basics', related: ['taux-de-change', 't2', 'fixing'] },
  { slug: 't2', term: 'T+2', shortFr: 'Date de valeur spot = 2 jours ouvrés après la transaction.', shortEn: 'Spot value date = 2 business days after the trade.', longFr: 'Le T+2 est la convention standard pour la livraison des transactions spot. Pour une transaction le mardi, la livraison a lieu le jeudi. Si le T+2 tombe un jour férié (weekend ou jour férié MA), on reporte au jour ouvré suivant.', longEn: 'T+2 is the standard convention for spot value date. For a Tuesday trade, delivery happens on Thursday. If T+2 falls on a holiday (weekend or MA public holiday), it rolls to the next business day.', category: 'fx-basics', related: ['spot', 'holiday-calendar'] },
  { slug: 'virement-billet', term: 'Virement vs Billet', shortFr: 'Virement = wire transfer, billets = banknotes. Spreads très différents.', shortEn: 'Virement = wire, billets = banknotes. Very different spreads.', longFr: 'Le virement (wire transfer) est une opération scripturale entre banques — spread typique 0.05-0.15%. Le billet (banknotes) implique un transport physique, assurance, immobilisation — spread typique 1-3%.', longEn: 'A virement (wire) is a book entry between banks — typical spread 0.05-0.15%. Bills (banknotes) involve physical transport, insurance, immobilisation — typical spread 1-3%.', category: 'fx-basics', related: ['spread'] },

  // === FX ADVANCED ===
  { slug: 'cip', term: 'CIP (Covered Interest Parity)', shortFr: 'Parité de taux d\'intérêt couverte : F = S × (1+rd×T) / (1+rf×T).', shortEn: 'Covered interest parity: F = S × (1+rd×T) / (1+rf×T).', longFr: 'La CIP est une relation d\'arbitrage sans risque : le taux forward doit refléter le différentiel de taux d\'intérêt entre les deux devises, sinon un arbitrage est possible. F = S × (1 + r_d × T) / (1 + r_f × T).', longEn: 'CIP is a no-arbitrage relation: the forward rate must reflect the interest rate differential, otherwise arbitrage is possible. F = S × (1 + r_d × T) / (1 + r_f × T).', category: 'fx-advanced', related: ['forward', 'taux-sans-arb'], examples: ['EUR/MAD spot 10.85, r_d MAD=2.5%, r_f EUR=2.25%, T=0.25 → F ≈ 10.851'] },
  { slug: 'xcs', term: 'Cross-Currency Basis (XCS)', shortFr: 'Écart entre CIP théorique et swap FX réel, dû au risque de contrepartie.', shortEn: 'Gap between theoretical CIP and actual FX swap, due to counterparty risk.', longFr: 'La base de change (XCS) mesure l\'écart entre le taux forward théorique (CIP) et le taux forward réel observable sur le marché des swaps. Depuis 2008, EUR/USD basis peut atteindre +30 bps. Le MAD, devise gérée, a un basis proche de 0.', longEn: 'The cross-currency basis (XCS) measures the gap between the theoretical CIP forward and the actual swap-market forward. Since 2008, the EUR/USD basis can reach +30 bps. The MAD, a managed currency, has a basis near 0.', category: 'fx-advanced', related: ['cip', 'forward'] },
  { slug: 'forward', term: 'Forward', shortFr: 'Contrat de change à terme avec livraison et taux fixés aujourd\'hui.', shortEn: 'Forward contract: rate and delivery date fixed today.', longFr: 'Un forward est un accord bilatéral d\'échanger deux devises à un taux et une date future convenus aujourd\'hui. Pas d\'échange initial. Régulé par la Circ. OC 01/2024 pour les entreprises marocaines.', longEn: 'A forward is a bilateral agreement to exchange two currencies at a rate and future date fixed today. No initial exchange. Regulated by Circ. OC 01/2024 for Moroccan corporates.', category: 'fx-advanced', related: ['cip', 'forward-points', 'swap'], examples: ['Forward EUR/MAD 3M : taux fixé aujourd\'hui, livraison dans 3 mois'] },
  { slug: 'forward-points', term: 'Forward points / Points de swap', shortFr: 'Différence entre forward et spot, exprimée en pips.', shortEn: 'Difference between forward and spot, in pips.', longFr: 'Les forward points représentent l\'écart entre le taux forward et le taux spot. F - S. Ils sont positifs si la devise domestique a un taux directeur plus élevé (carry trade positif) et négatifs sinon.', longEn: 'Forward points are the difference between the forward and spot rates. F - S. They are positive if the domestic currency has a higher policy rate (positive carry) and negative otherwise.', category: 'fx-advanced', related: ['forward', 'cip', 'pip'] },
  { slug: 'swap', term: 'Swap de change', shortFr: 'Double forward simultané : achat spot + vente forward (ou inverse).', shortEn: 'Simultaneous dual forward: buy spot + sell forward (or reverse).', longFr: 'Un swap de change est la combinaison d\'un spot et d\'un forward inverse. Utilisé pour rouler une position (rollover) ou pour swapper temporairement une devise sans livraison.', longEn: 'An FX swap is a combination of a spot and a reverse forward. Used to roll a position or to temporarily swap a currency without delivery.', category: 'fx-advanced', related: ['forward', 'rollover'] },
  { slug: 'rollover', term: 'Rollover / Prorogation', shortFr: 'Reconduction d\'un forward à une nouvelle échéance.', shortEn: 'Extending a forward to a new maturity date.', longFr: 'Le rollover consiste à dénouer un forward arrivant à maturité et à en booker un nouveau pour une période ultérieure. Le coût est la différence de points de swap entre les deux maturités.', longEn: 'A rollover unwinds a forward at maturity and books a new one for a later period. The cost is the swap points difference between the two maturities.', category: 'fx-advanced', related: ['forward', 'swap'] },
  { slug: 'option-vanilla', term: 'Option vanilla', shortFr: 'Droit (non obligation) d\'acheter/vendre à un strike donné.', shortEn: 'Right (not obligation) to buy/sell at a given strike.', longFr: 'Une option vanilla donne à l\'acheteur le droit, mais pas l\'obligation, d\'acheter (call) ou vendre (put) une devise à un prix d\'exercice (strike) à une date future. Coût = prime.', longEn: 'A vanilla option gives the buyer the right, but not the obligation, to buy (call) or sell (put) a currency at a strike price on a future date. Cost = premium.', category: 'fx-advanced', related: ['forward', 'instruments'] },
  { slug: 'option-exotique', term: 'Option exotique', shortFr: 'Option à payoff non-standard (knock-out, barrier, digital, etc.).', shortEn: 'Non-standard payoff option (knock-out, barrier, digital...).', longFr: 'Les options exotiques ont des caractéristiques de payoff non-standard (barrier, knock-out, lookback, digital). INTERDITES par la Circ. OC 01/2024 pour les entreprises marocaines.', longEn: 'Exotic options have non-standard payoff characteristics (barrier, knock-out, lookback, digital). PROHIBITED by Circ. OC 01/2024 for Moroccan corporates.', category: 'fx-advanced', related: ['option-vanilla', 'circ-oc-01-2024'] },
  { slug: 'ndf', term: 'NDF (Non-Deliverable Forward)', shortFr: 'Forward sans livraison physique, réglé en différentiel.', shortEn: 'Forward without physical delivery, settled in differential.', longFr: 'Un NDF est un forward sur une devise non convertible (historiquement le MAD avant 2018) qui se règle en cash, sans livraison de devise. INTERDIT pour le MAD depuis la convertibilité du compte capital (2018).', longEn: 'An NDF is a forward on a non-convertible currency (historically MAD pre-2018) cash-settled without currency delivery. PROHIBITED for MAD since capital account convertibility (2018).', category: 'fx-advanced', related: ['forward', 'convertibilite'] },
  { slug: 'volatilite-implicite', term: 'Volatilité implicite', shortFr: 'Vol future attendue par le marché, dérivée des prix d\'options.', shortEn: 'Future vol expected by the market, derived from option prices.', longFr: 'La volatilité implicite (VI) est la volatilité annualisée que le marché "price" pour une devise à une échéance donnée. Elle se déduit des primes d\'options via Black-Scholes. Une VI élevée = marché stressé.', longEn: 'Implied volatility (IV) is the annualised vol the market prices in for a currency at a given maturity. It is derived from option premiums via Black-Scholes. High IV = stressed market.', category: 'fx-advanced', related: ['option-vanilla', 'vol-surface'] },
  { slug: 'vol-surface', term: 'Surface de volatilité', shortFr: 'VI par strike et par maturité — visualise la "peur" du marché.', shortEn: 'IV by strike and maturity — visualises market "fear".', longFr: 'La surface de volatilité (vol surface) est la matrice VI pour chaque combinaison strike × maturité. Le skew (asymétrie) indique si le marché se protège plus à la hausse qu\'à la baisse.', longEn: 'The volatility surface is the IV matrix for each strike × maturity combination. The skew indicates whether the market is hedging more for upside than downside moves.', category: 'fx-advanced', related: ['volatilite-implicite'] },

  // === MAD-SPECIFIC ===
  { slug: 'panier-bkam', term: 'Panier BKAM 60/40', shortFr: 'Bask reference: 60% EUR + 40% USD, K=10.49.', shortEn: 'Basket ref: 60% EUR + 40% USD, K=10.49.', longFr: 'Le panier de référence BKAM est composé à 60% d\'EUR et 40% d\'USD, avec un coefficient K = 10.49. Formule : USD/MAD_central = K / (0.60 × EUR/USD + 0.40). Le MAD s\'arrime à ce panier depuis 2018.', longEn: 'The BKAM reference basket is 60% EUR + 40% USD, with K = 10.49. Formula: USD/MAD_central = K / (0.60 × EUR/USD + 0.40). The MAD has been pegged to this basket since 2018.', category: 'mad-specific', related: ['bande-5-pct', 'fixing', 'monia'] },
  { slug: 'bande-5-pct', term: 'Bande de fluctuation ±5%', shortFr: 'Cage réglementaire BKAM: ±5% autour de la parité centrale du panier.', shortEn: 'BKAM regulatory band: ±5% around basket central parity.', longFr: 'Depuis mars 2020 (Phase II), le MAD peut fluctuer ±5% autour de la parité centrale calculée par le panier. En pratique, la fluctuation effective reste dans ±1.5% en 2025-2026.', longEn: 'Since March 2020 (Phase II), the MAD can fluctuate ±5% around the basket central parity. In practice, the effective range stays within ±1.5% in 2025-2026.', category: 'mad-specific', related: ['panier-bkam', 'fixing'] },
  { slug: 'fixing', term: 'Fixing BKAM', shortFr: 'Cours de référence publié à 12:30 et 16:15 (heure Casablanca).', shortEn: 'Reference rate published 12:30 and 16:15 (Casablanca time).', longFr: 'Bank Al-Maghrib publie deux fixings par jour : 12:30 (intraday, milieu de session MIC) et 16:15 (clôture, basé sur les transactions réelles). Le fixing 16:15 est la référence utilisée pour les transactions.', longEn: 'Bank Al-Maghrib publishes two fixings per day: 12:30 (intraday, mid-MIC session) and 16:15 (close, based on actual transactions). The 16:15 fixing is the reference used for transactions.', category: 'mad-specific', related: ['panier-bkam', 'mic-bkam'] },
  { slug: 'mic-bkam', term: 'MIC (Marché Interbancaire de Change)', shortFr: 'Plateforme de change interbancaire BAM. Heures: 8:30-15:30 (Ramadan: 9:15-13:15).', shortEn: 'BAM interbank FX platform. Hours: 8:30-15:30 (Ramadan: 9:15-13:15).', longFr: 'Le MIC est la plateforme où les banques agréées échangent le MAD contre les devises étrangères. Il fonctionne en semaine sauf jours fériés, avec des horaires réduits pendant le Ramadan (UTC+0 au lieu de UTC+1).', longEn: 'The MIC is the platform where licensed banks exchange MAD for foreign currencies. It runs weekdays except holidays, with reduced hours during Ramadan (UTC+0 instead of UTC+1).', category: 'mad-specific', related: ['fixing', 'ramadan-trading-hours'] },
  { slug: 'ramadan-trading-hours', term: 'Heures de marché Ramadan', shortFr: 'MIC réduit pendant Ramadan: 9:15-13:15 au lieu de 8:30-15:30.', shortEn: 'MIC reduced during Ramadan: 9:15-13:15 instead of 8:30-15:30.', longFr: 'Pendant le Ramadan, le Maroc passe en UTC+0 (vs UTC+1 le reste de l\'année). Le MIC adapte ses horaires : 9:15-13:15 au lieu de 8:30-15:30. Le fixing passe à 14:00 au lieu de 16:15.', longEn: 'During Ramadan, Morocco moves to UTC+0 (vs UTC+1 the rest of the year). The MIC adjusts: 9:15-13:15 instead of 8:30-15:30. The fixing moves to 14:00 instead of 16:15.', category: 'mad-specific', related: ['mic-bkam', 'fixing'] },
  { slug: 'uma-convention', term: 'Convention UMA', shortFr: 'Taux de change bilatéral UMA (TND, DZD, LYD) fixé par la convention.', shortEn: 'Bilateral UMA FX rate (TND, DZD, LYD) set by convention.', longFr: 'Les taux de change TND, DZD, LYD contre MAD ne sont pas déterminés par le marché mais par la Convention UMA (Union du Maghreb Arabe) de paiement bilatéral. Ils sont relativement stables mais déconnectés des taux de marché.', longEn: 'TND, DZD, LYD exchange rates against MAD are not market-determined but set by the UMA (Arab Maghreb Union) bilateral payment convention. They are relatively stable but disconnected from market rates.', category: 'mad-specific', related: ['bkam'] },
  { slug: 'monia', term: 'MONIA (Moroccan Overnight Index Average)', shortFr: 'Taux interbancaire overnight de référence, calculé par BAM.', shortEn: 'Overnight interbank reference rate, calculated by BAM.', longFr: 'Le MONIA est l\'équivalent marocain du SOFR (USD) ou de l\'€STR (EUR). C\'est le taux overnight moyen des transactions interbancaires non garanties. Il sert de référence pour le pricing des produits monétaires.', longEn: 'MONIA is the Moroccan equivalent of SOFR (USD) or €STR (EUR). It is the average overnight rate of unsecured interbank transactions. It serves as a reference for money-market product pricing.', category: 'mad-specific', related: ['politique-monetaire-bam', 'panier-bkam'] },
  { slug: 'convertibilite', term: 'Convertibilité du MAD', shortFr: 'Pleine convertibilité du compte courant depuis 1993, capital depuis 2018.', shortEn: 'Full current account convertibility since 1993, capital since 2018.', longFr: 'Le MAD a une pleine convertibilité de compte courant depuis 1993 (conformément aux statuts du FMI). La convertibilité du compte capital a été adoptée en 2018 (Phase II), avec un élargissement progressif des bandes.', longEn: 'The MAD has full current account convertibility since 1993 (per IMF Articles of Agreement). Capital account convertibility was adopted in 2018 (Phase II), with progressive band widening.', category: 'mad-specific', related: ['panier-bkam', 'bande-5-pct'] },
  { slug: 'phase-ii-2018', term: 'Phase II (2018)', shortFr: 'Élargissement progressif des bandes de fluctuation à ±5%.', shortEn: 'Progressive widening of fluctuation bands to ±5%.', longFr: 'Phase II du régime de change marocain : depuis 2018, les bandes de fluctuation s\'élargissent progressivement. Mars 2020 = ±5%. Phase III prévue pour 2027+ (élargissement à ±10% selon FMI).', longEn: 'Phase II of the Moroccan FX regime: since 2018, fluctuation bands widen progressively. March 2020 = ±5%. Phase III planned for 2027+ (widening to ±10% per IMF).', category: 'mad-specific', related: ['bande-5-pct', 'convertibilite'] },
  { slug: 'billet-200', term: 'Billet 200 MAD', shortFr: 'Plus grosse coupure MAD, émission BAM depuis 2002.', shortEn: 'Largest MAD denomination, BAM issuance since 2002.', longFr: 'Le billet de 200 MAD est la plus grosse coupure en circulation. Il est émis par Bank Al-Maghrib depuis 2002. La série actuelle (Type 2013) intègre des éléments de sécurité modernes (fil de sécurité, encre optiquement variable).', longEn: 'The 200 MAD banknote is the largest denomination in circulation. Issued by Bank Al-Maghrib since 2002. The current series (Type 2013) features modern security elements (security thread, optically variable ink).', category: 'mad-specific', related: ['billet'] },

  // === REGULATION OC ===
  { slug: 'circ-oc-01-2024', term: 'Circ. OC 01/2024', shortFr: 'Circulaire Office des Changes 2024 sur les couvertures de change autorisées.', shortEn: 'OC 2024 circular on authorized FX hedging instruments.', longFr: 'La Circ. OC 01/2024 encadre les instruments de couverture de change pour les entreprises résidentes. Autorisés : forwards, FX swaps, options vanilla. INTERDITS : options exotiques, binaires, produits à levier, options digitales.', longEn: 'Circ. OC 01/2024 regulates FX hedging instruments for Moroccan-resident corporates. Authorized: forwards, FX swaps, vanilla options. PROHIBITED: exotic options, binaries, leveraged products, digital options.', category: 'regulation-oc', related: ['forward', 'option-vanilla', 'option-exotique'] },
  { slug: 'igoc', term: 'IGOC (Instruction Générale des Opérations de Change)', shortFr: 'Cadre réglementaire général des opérations de change au Maroc.', shortEn: 'General regulatory framework for FX operations in Morocco.', longFr: 'L\'IGOC est l\'instruction de référence publiée par Bank Al-Maghrib qui fixe les règles relatives aux opérations de change, transferts de fonds, et investissements à l\'étranger. Émise en 2017, mise à jour 2024.', longEn: 'The IGOC is the reference instruction published by Bank Al-Maghrib setting rules for FX operations, fund transfers, and foreign investments. Issued 2017, updated 2024.', category: 'regulation-oc', related: ['circ-oc-01-2024', 'office-des-changes'] },
  { slug: 'office-des-changes', term: 'Office des Changes (OC)', shortFr: 'Autorité marocaine de régulation des changes et mouvements de capitaux.', shortEn: 'Moroccan authority regulating FX and capital movements.', longFr: 'L\'Office des Changes est l\'autorité administrative qui contrôle les mouvements de capitaux entre le Maroc et l\'étranger. Il émet circulaires, instructions et communiqués. Il supervise également les déclarations des opérateurs.', longEn: 'The Office des Changes is the administrative authority that controls capital movements between Morocco and abroad. It issues circulars, instructions and communiqués. It also supervises operator declarations.', category: 'regulation-oc', related: ['igoc', 'circ-oc-01-2024'] },
  { slug: 'repatriation-150-jours', term: 'Répatriement 150 jours', shortFr: 'Délai max de rapatriement des recettes d\'exportation: 150 jours.', shortEn: 'Max delay for repatriation of export proceeds: 150 days.', longFr: 'Selon la Circ. 3/2019, les exportateurs marocains doivent rapatrier leurs recettes de change dans un délai de 150 jours suivant l\'expédition. Au-delà, sanctions de 5% par mois de retard.', longEn: 'Per Circ. 3/2019, Moroccan exporters must repatriate their FX proceeds within 150 days of shipment. Beyond that, penalties of 5% per month of delay apply.', category: 'regulation-oc', related: ['circ-exportations', 'igoc'] },
  { slug: 'cpec-cde', term: 'CDE / CPEC', shortFr: 'Compte en Devises Étrangères / Compte Professionnel en Devises.', shortEn: 'Foreign Currency Account / Professional Foreign Currency Account.', longFr: 'Le CDE permet à toute personne physique résidente de détenir jusqu\'à 100% de ses revenus en devises. Le CPEC est réservé aux exportateurs (CA export > 5M MAD/an) et permet de conserver 70% des recettes export en devises.', longEn: 'The CDE allows any resident individual to hold up to 100% of their income in foreign currency. The CPEC is reserved for exporters (export revenue > 5M MAD/year) and allows keeping 70% of export proceeds in FX.', category: 'regulation-oc', related: ['igoc', 'office-des-changes'] },
  { slug: 'allocation-voyage', term: 'Allocation voyage', shortFr: 'Plafond annuel en devises pour voyages: 45 000 MAD/personne.', shortEn: 'Annual FX allowance for travel: 45,000 MAD/person.', longFr: 'La Circ. 2/2019 fixe les allocations en devises pour voyages touristiques (45 000 MAD/an), pèlerinage (25 000 MAD Hajj, 15 000 MAD Omra), soins médicaux (200 000 MAD/an), et études à l\'étranger.', longEn: 'Circ. 2/2019 sets FX allowances for tourist travel (45,000 MAD/yr), pilgrimage (25,000 MAD Hajj, 15,000 MAD Omra), medical care (200,000 MAD/yr), and studies abroad.', category: 'regulation-oc', related: ['igoc'] },
  { slug: 'domiciliation', term: 'Domiciliation bancaire', shortFr: 'Toute importation >50 000 MAD doit être domiciliée auprès d\'une banque.', shortEn: 'Any import >50,000 MAD must be domiciled with a bank.', longFr: 'La domiciliation est l\'obligation pour toute importation de biens dont la valeur dépasse 50 000 MAD de la domicilier auprès d\'une banque agréée avant le dédouanement. La Circ. 2/2012 détaille la procédure.', longEn: 'Domiciliation is the obligation for any goods import exceeding 50,000 MAD to be domiciled with a licensed bank before customs clearance. Circ. 2/2012 details the procedure.', category: 'regulation-oc', related: ['circ-importations'] },
  { slug: 'circ-importations', term: 'Circ. 2/2012 (Importations)', shortFr: 'Cadre réglementaire des paiements d\'importation de biens et services.', shortEn: 'Regulatory framework for goods and services import payments.', longFr: 'La Circ. 2/2012 régit le paiement des importations de biens et services: domiciliation obligatoire, plafonds d\'avances, délais de règlement (120 jours après dédouanement).', longEn: 'Circ. 2/2012 governs import payments for goods and services: mandatory domiciliation, advance caps, payment delays (120 days post-clearance).', category: 'regulation-oc', related: ['domiciliation', 'igoc'] },
  { slug: 'circ-exportations', term: 'Circ. 3/2019 (Exportations)', shortFr: 'Rapatriement obligatoire des recettes d\'exportation sous 150 jours.', shortEn: 'Mandatory repatriation of export proceeds within 150 days.', longFr: 'La Circ. 3/2019 fixe l\'obligation de rapatrier les recettes d\'exportation sous 150 jours (90 jours pour hydrocarbures, 60 jours pour services). 30% doivent être cédés à BAM sous 30 jours.', longEn: 'Circ. 3/2019 mandates repatriation of export proceeds within 150 days (90 for hydrocarbons, 60 for services). 30% must be sold to BAM within 30 days.', category: 'regulation-oc', related: ['repatriation-150-jours'] },
  { slug: 'reporting-pme', term: 'Reporting PME OC', shortFr: 'PME importatrices/exportatrices >500K MAD/mois: déclaration mensuelle.', shortEn: 'Importing/exporting SMEs >500K MAD/month: monthly declaration.', longFr: 'La Circ. OC 01/2024 impose aux PME (CA import/export >500 000 MAD/mois) un reporting mensuel détaillé des flux de change, contreparties, délais de règlement et instruments de couverture utilisés.', longEn: 'Circ. OC 01/2024 requires SMEs (import/export turnover >500,000 MAD/month) to file a detailed monthly report on FX flows, counterparties, payment delays, and hedging instruments used.', category: 'regulation-oc', related: ['circ-oc-01-2024'] },
  { slug: 'loi-19-14', term: 'Loi 19-14', shortFr: 'Loi 2014 criminalisant les infractions de change au Maroc.', shortEn: '2014 law criminalizing FX violations in Morocco.', longFr: 'La Loi 19-14 modifie et complète le Dahir portant loi n° 1-73-318 du 15 Moharrem 1393 (1973) réprimant les infractions à la réglementation des changes. Sanctions: amendes + emprisonnement.', longEn: 'Law 19-14 amends and supplements the Dahir carrying Law 1-73-318 of 15 Moharrem 1393 (1973) punishing violations of FX regulation. Sanctions: fines + imprisonment.', category: 'regulation-oc', related: ['loi-103-12', 'office-des-changes'] },
  { slug: 'loi-103-12', term: 'Loi 103-12', shortFr: 'Loi bancaire marocaine 2014: cadre prudentiel BAM.', shortEn: 'Moroccan banking law 2014: BAM prudential framework.', longFr: 'La Loi 103-12 relative aux établissements de crédit et organismes assimilés pose le cadre prudentiel pour les banques marocaines. BAM Al-Maghrib supervise, contrôle et sanctionne. Ratios: Tier 1 ≥ 9%, solvabilité ≥ 12%.', longEn: 'Law 103-12 on credit institutions and similar bodies sets the prudential framework for Moroccan banks. Bank Al-Maghrib supervises, controls and sanctions. Ratios: Tier 1 ≥ 9%, solvency ≥ 12%.', category: 'regulation-oc', related: ['loi-19-14'] },

  // === RISK MANAGEMENT ===
  { slug: 'risque-transactionnel', term: 'Risque transactionnel', shortFr: 'Exposition au change sur flux commerciaux déjà engagés.', shortEn: 'FX exposure on already-committed commercial flows.', longFr: 'Le risque transactionnel est l\'exposition au change sur des transactions déjà contractées (facture fournisseur ou client signée). Il est certain et quantifiable. Horizon: du booking au paiement.', longEn: 'Transactional risk is FX exposure on already-contracted transactions (signed supplier or client invoice). It is certain and quantifiable. Horizon: from booking to payment.', category: 'risk-management', related: ['risque-economique', 'forward'] },
  { slug: 'risque-economique', term: 'Risque économique', shortFr: 'Exposition au change sur flux prévisionnels (non encore contractés).', shortEn: 'FX exposure on forecasted flows (not yet contracted).', longFr: 'Le risque économique (ou translationnel) est l\'exposition sur des flux prévisionnels (budget, business plan). Il est incertain. Horizon: 1-3 ans. Couverture via options, rolling forwards, ou budget-based hedges.', longEn: 'Economic (or translational) risk is exposure on forecasted flows (budget, business plan). It is uncertain. Horizon: 1-3 years. Hedged via options, rolling forwards, or budget-based hedges.', category: 'risk-management', related: ['risque-transactionnel', 'option-vanilla'] },
  { slug: 'risque-contrepartie', term: 'Risque de contrepartie', shortFr: 'Risque que la contrepartie ne honore pas ses engagements.', shortEn: 'Risk that the counterparty does not honor its commitments.', longFr: 'Le risque de contrepartie est le risque qu\'une banque ou un client ne respecte pas ses obligations contractuelles. Mitigé par les CSA (Credit Support Annex), les appels de marge, et les limites de crédit.', longEn: 'Counterparty risk is the risk that a bank or client does not meet its contractual obligations. Mitigated by CSAs (Credit Support Annex), margin calls, and credit limits.', category: 'risk-management', related: ['risque-transactionnel'] },
  { slug: 'var', term: 'VaR (Value at Risk)', shortFr: 'Perte maximale sur un horizon donné, avec un niveau de confiance.', shortEn: 'Max loss over a given horizon, at a confidence level.', longFr: 'La Value at Risk est la perte maximale potentielle sur un horizon donné (1j, 10j, 1an) avec un niveau de confiance donné (95%, 99%). Utilisée pour le reporting risk management Bâle III.', longEn: 'Value at Risk is the maximum potential loss over a given horizon (1d, 10d, 1y) at a given confidence level (95%, 99%). Used for Basel III risk management reporting.', category: 'risk-management', related: ['risque-transactionnel'] },
  { slug: 'policy-couverture', term: 'Politique de couverture', shortFr: 'Document interne définissant la stratégie FX de l\'entreprise.', shortEn: 'Internal document defining the corporate FX hedging strategy.', longFr: 'Une politique de couverture FX documente: exposition admissible (%), instruments autorisés, plafonds par contrepartie, reporting, gouvernance. Recommandée par l\'OC 01/2024 pour les PME > 5M MAD/mois d\'exposition.', longEn: 'An FX hedging policy documents: allowable exposure (%), authorized instruments, counterparty limits, reporting, governance. Recommended by OC 01/2024 for SMEs > 5M MAD/month exposure.', category: 'risk-management', related: ['circ-oc-01-2024'] },
  { slug: 'stop-loss', term: 'Stop-loss FX', shortFr: 'Ordre conditionnel pour fermer une position si la perte dépasse un seuil.', shortEn: 'Conditional order to close a position if loss exceeds a threshold.', longFr: 'Un stop-loss FX est un seuil de perte maximal prédéfini. Si le marché le touche, la position est automatiquement fermée. Limite les pertes mais peut sortir trop tôt en cas de bruit.', longEn: 'A FX stop-loss is a predefined max-loss threshold. If the market hits it, the position is automatically closed. Limits losses but may exit too early on noise.', category: 'risk-management', related: ['var', 'risque-transactionnel'] },

  // === BANKING MOROCCO ===
  { slug: 'attijariwafa', term: 'Attijariwafa Bank', shortFr: '1ère banque marocaine par les actifs. Cotée à Casablanca.', shortEn: '#1 Moroccan bank by assets. Listed in Casablanca.', longFr: 'Attijariwafa Bank est la première banque marocaine par les actifs (~600 Mds MAD). Issue de la fusion BCM/Wafa Bank en 2003. Cotée à la Bourse de Casablanca, présente dans 25+ pays africains.', longEn: 'Attijariwafa Bank is the leading Moroccan bank by assets (~600B MAD). Born from the 2003 BCM/Wafa Bank merger. Listed on the Casablanca Stock Exchange, present in 25+ African countries.', category: 'banking-morocco', related: ['banque-maroc', 'banque-populaire'] },
  { slug: 'banque-populaire', term: 'Banque Populaire du Maroc', shortFr: '2ème banque marocaine, réseau coopératif dense.', shortEn: '#2 Moroccan bank, dense cooperative network.', longFr: 'Le Groupe Banque Populaire (BCP) est la 2ème banque marocaine. Réseau de caisses régionales issues du mouvement coopératif. Très présente dans la banque de détail, l\'agriculture, et la diaspora marocaine en Europe.', longEn: 'Banque Populaire Group (BCP) is the 2nd Moroccan bank. Network of regional cooperatives. Strong presence in retail, agriculture, and Moroccan diaspora in Europe.', category: 'banking-morocco', related: ['attijariwafa'] },
  { slug: 'bmce', term: 'BMCE Bank (Bank of Africa)', shortFr: '3ème banque marocaine, présence forte en Afrique subsaharienne.', shortEn: '#3 Moroccan bank, strong SSA presence.', longFr: 'BMCE Bank of Africa est la 3ème banque marocaine (renommée Bank of Africa en 2020). Très active en Afrique subsaharienne, leader du marché marocain des transferts MRE (Marocains Résidant à l\'Étranger).', longEn: 'BMCE Bank of Africa is the 3rd Moroccan bank (renamed Bank of Africa in 2020). Very active in sub-Saharan Africa, leader in the Moroccan market for MRE (Moroccans Residing Abroad) transfers.', category: 'banking-morocco', related: ['attijariwafa', 'mre'] },
  { slug: 'cih', term: 'CIH Bank', shortFr: '4ème banque marocaine, spécialiste de l\'immobilier.', shortEn: '#4 Moroccan bank, real-estate specialist.', longFr: 'CIH Bank (Crédit Immobilier et Hôtelier) est la 4ème banque marocaine. Spécialisée historiquement dans le financement immobilier et hôtelier, elle a diversifié vers la banque de détail, corporate, et islamique.', longEn: 'CIH Bank (Real Estate and Hotel Credit) is the 4th Moroccan bank. Historically specialized in real estate and hotel financing, it has diversified into retail, corporate, and Islamic banking.', category: 'banking-morocco', related: ['banque-maroc'] },
  { slug: 'sg-maroc', term: 'Société Générale Maroc', shortFr: 'Filiale du groupe Société Générale, banque universelle.', shortEn: 'Subsidiary of Société Générale group, universal bank.', longFr: 'Société Générale Maroc est la filiale marocaine du groupe français Société Générale. Banque universelle, présente dans la banque de détail, corporate, investment banking.', longEn: 'Société Générale Maroc is the Moroccan subsidiary of the French Société Générale group. Universal bank, present in retail, corporate, and investment banking.', category: 'banking-morocco', related: ['banque-maroc'] },
  { slug: 'mre', term: 'MRE (Marocains Résidant à l\'Étranger)', shortFr: 'Diaspora marocaine: ~5M personnes, transferts = 7% du PIB.', shortEn: 'Moroccan diaspora: ~5M people, transfers = 7% of GDP.', longFr: 'Les MRE (Marocains Résidant à l\'Étranger) représentent une communauté de ~5 millions de personnes, principalement en Europe. Leurs transferts de fonds vers le Maroc atteignent ~7% du PIB, un record mondial.', longEn: 'MREs (Moroccans Residing Abroad) represent a community of ~5 million people, mainly in Europe. Their remittances to Morocco reach ~7% of GDP, a world record.', category: 'banking-morocco', related: ['bmce'] },

  // === MONETARY POLICY ===
  { slug: 'taux-directeur-bam', term: 'Taux directeur BAM', shortFr: 'Taux de la politique monétaire BAM: 2.75% en 2025.', shortEn: 'BAM policy rate: 2.75% in 2025.', longFr: 'Le taux directeur de Bank Al-Maghrib est l\'instrument principal de la politique monétaire marocaine. Il a évolué: 3.00% (2024) → 2.75% (2025). Il sert de référence pour le MONIA, les facilités permanentes, et la courbe des taux.', longEn: 'The Bank Al-Maghrib policy rate is the main instrument of Moroccan monetary policy. It evolved: 3.00% (2024) → 2.75% (2025). It serves as the reference for MONIA, standing facilities, and the yield curve.', category: 'monetary-policy', related: ['monia', 'reserve-bancaire'] },
  { slug: 'reserve-bancaire', term: 'Réserves bancaires', shortFr: 'Ratio de réserves obligatoires BAM: 3% des dépôts à vue.', shortEn: 'BAM reserve requirement ratio: 3% of demand deposits.', longFr: 'Le coefficient de réserves obligatoires appliqué par Bank Al-Maghrib est de 3% sur les dépôts à vue et comptes courants. Les banques doivent déposer ce montant à BAM, non rémunéré.', longEn: 'The reserve requirement ratio applied by Bank Al-Maghrib is 3% on demand deposits and current accounts. Banks must deposit this amount with BAM, non-interest bearing.', category: 'monetary-policy', related: ['taux-directeur-bam', 'monia'] },
  { slug: 'reserve-change', term: 'Réserves de change BAM', shortFr: 'Encours BAM en devises: ~36 Mds USD (2025).', shortEn: 'BAM FX reserves: ~36B USD (2025).', longFr: 'Les réserves de change de BAM s\'élèvent à environ 36 milliards USD (2025), soit ~4.2 mois d\'importations. La cible IMF est 5+ mois. La BAM intervient pour défendre la parité panier.', longEn: 'BAM FX reserves are around 36 billion USD (2025), or ~4.2 months of imports. The IMF target is 5+ months. BAM intervenes to defend the basket parity.', category: 'monetary-policy', related: ['taux-directeur-bam', 'panier-bkam'] },
  { slug: 'facilites-permanentes', term: 'Facilités permanentes', shortFr: 'BAM refinance/place banques overnight via 2 facilités.', shortEn: 'BAM lends/deposits banks overnight via 2 facilities.', longFr: 'BAM opère deux facilités permanentes: la facilité de prêt marginal (taux = taux directeur + 2%, plafonné) et la facilité de dépôt (taux = taux directeur − 2%, plancher). Elles encadrent le MONIA.', longEn: 'BAM operates two standing facilities: the marginal lending facility (rate = policy rate + 2%, capped) and the deposit facility (rate = policy rate − 2%, floored). They frame the MONIA.', category: 'monetary-policy', related: ['monia', 'taux-directeur-bam'] },
  { slug: 'open-market', term: 'Opérations d\'open market BAM', shortFr: 'Adjudications 7j/14j/28j, repo inverse, swaps de change.', shortEn: '7d/14d/28d tenders, reverse repo, FX swaps.', longFr: 'BAM intervient sur le marché monétaire via des adjudications de pensions livrées (7j, 14j, 28j), des prises en pension (repos inverses), et des swaps de change. Ces opérations absorbent ou injectent de la liquidité.', longEn: 'BAM operates on the money market via repo tenders (7d, 14d, 28d), reverse repos, and FX swaps. These operations absorb or inject liquidity.', category: 'monetary-policy', related: ['monia', 'taux-directeur-bam'] },

  // === INSTRUMENTS ===
  { slug: 'ndf-instrument', term: 'NDF (instrument)', shortFr: 'Forward cash-settled sans livraison, jadis pour MAD pré-2018.', shortEn: 'Cash-settled forward without delivery, formerly for MAD pre-2018.', longFr: 'Le NDF (Non-Deliverable Forward) est un forward sur devises non convertibles qui se règle par différentiel cash. Pour le MAD, les NDF sont devenus obsolètes depuis la convertibilité du compte capital (2018).', longEn: 'An NDF (Non-Deliverable Forward) is a forward on non-convertible currencies settled by cash differential. For MAD, NDFs became obsolete after capital account convertibility (2018).', category: 'instruments', related: ['forward', 'convertibilite'] },
  { slug: 'swap-currency', term: 'Swap cambiste (FX swap)', shortFr: 'Achat spot + vente forward simultanés, ou inverse.', shortEn: 'Buy spot + sell forward simultaneously, or reverse.', longFr: 'Le swap cambiste est l\'échange simultané d\'une devise contre une autre à deux dates différentes. Utilisé par les banques pour la gestion de trésorerie, par les entreprises pour le roulement de position, et par les BC pour la politique monétaire.', longEn: 'An FX swap is the simultaneous exchange of one currency for another at two different dates. Used by banks for treasury management, by corporates for position rolling, and by central banks for monetary policy.', category: 'instruments', related: ['forward', 'swap'] },
  { slug: 'cross-currency-swap', term: 'Cross-currency swap (CCS)', shortFr: 'Swap de taux + change sur plusieurs années. Échange de principal.', shortEn: 'Interest rate + FX swap over multiple years. Principal exchange.', longFr: 'Le CCS (Cross-Currency Swap) combine un swap de taux et un swap de change. Il y a échange de principal initial et final, plus échanges de coupons périodiques. Maturités 2-30 ans typiques.', longEn: 'A CCS (Cross-Currency Swap) combines an interest rate swap and an FX swap. There is initial and final principal exchange, plus periodic coupon exchanges. Maturities 2-30 years typical.', category: 'instruments', related: ['swap', 'xcs'] },
  { slug: 'swap-change-base', term: 'Basis swap', shortFr: 'Swap de change à 3M/6M, benchmark sur points de swap.', shortEn: '3M/6M FX swap, benchmarked on swap points.', longFr: 'Le basis swap (FX swap) est la forme la plus liquide du marché des changes. C\'est l\'échange d\'une devise contre une autre à deux dates (typiquement spot vs 3M), avec réversion implicite au taux forward. Le différentiel (basis) reflète la liquidité interbancaire.', longEn: 'The basis swap (FX swap) is the most liquid form of FX market. It is the exchange of one currency for another at two dates (typically spot vs 3M), with implicit reversion at the forward rate. The differential (basis) reflects interbank liquidity.', category: 'instruments', related: ['swap', 'xcs'] },
  { slug: 'ccs-mad', term: 'CCS MAD', shortFr: 'Cross-currency swap en MAD: rare, principalement avec Trésor.', shortEn: 'MAD cross-currency swap: rare, mainly with Treasury.', longFr: 'Les CCS en MAD sont rares en raison de la nature gérée de la devise. Le Trésor marocain émet occasionnellement des eurobonds swapés en MAD. Les banques multilatérales utilisent aussi des CCS pour le financement de projets.', longEn: 'CCS in MAD are rare due to the managed nature of the currency. The Moroccan Treasury occasionally issues eurobonds swapped into MAD. Multilateral banks also use CCS for project financing.', category: 'instruments', related: ['cross-currency-swap'] },
];

// Helper functions
export function getTermBySlug(slug: string): GlossaryTerm | undefined {
  return GLOSSARY.find((t) => t.slug === slug);
}

export function getRelatedTerms(slug: string): GlossaryTerm[] {
  const term = getTermBySlug(slug);
  if (!term) return [
  { slug: 'aed-mad', term: "AED/MAD", shortFr: "Paire de change Dirham émirati contre Dirham marocain.", shortEn: "Emirati Dirham vs Moroccan Dirham currency pair.", longFr: "L'AED (Dirham des Émirats Arabes Unis) est la devise du Golfe la plus échangée contre le MAD en raison de la forte communauté marocaine à Dubaï. Le cross AED/MAD est sensible aux exportations, à la trésorerie des expatriés et à la position touristique.", longEn: "The AED (UAE Dirham) is the most traded Gulf currency against MAD due to the large Moroccan community in Dubai. The AED/MAD cross is sensitive to exports, expat remittances, and tourism flows.", category: 'fx-basics', related: ["taux-de-change","cross-rate"], examples: ["AED/MAD = 2.96 environ"] },
  { slug: 'mad-zone-convertibilite', term: "Zone de convertibilité du MAD", shortFr: "Régime de change semi-float du Dirham depuis 2018.", shortEn: "Semi-float exchange regime of the Dirham since 2018.", longFr: "Le MAD opère sous un régime de change géré (managed float) depuis janvier 2018, avec un panier de référence USD/EUR à ±2.5% autour d'un cours central ajusté périodiquement par BAM. Avant 2018, le MAD était quasi-peg à l'EUR.", longEn: "The MAD operates under a managed float regime since January 2018, with a USD/EUR reference basket at ±2.5% around a central rate periodically adjusted by BAM. Before 2018, the MAD was quasi-pegged to EUR.", category: 'monetary-policy', related: ["bande-de-fluctuation","panier-de-reference"], examples: [] },
  { slug: 'panier-de-reference', term: "Panier de référence BAM", shortFr: "Panier USD 60% / EUR 40% pour le cours central du MAD.", shortEn: "USD 60% / EUR 40% basket for MAD central rate.", longFr: "Le panier de référence de Bank Al-Maghrib (60% USD, 40% EUR) sert à calculer le cours central du MAD. La pondération reflète la structure du commerce extérieur marocain. Une hausse de l'USD face à l'EUR tend à déprécier le MAD.", longEn: "The Bank Al-Maghrib reference basket (60% USD, 40% EUR) is used to compute the MAD central rate. The weighting reflects Morocco's foreign trade structure. An USD rise against EUR tends to depreciate the MAD.", category: 'monetary-policy', related: ["bande-de-fluctuation","bam"], examples: [] },
  { slug: 'cours-central', term: "Cours central", shortFr: "Taux de référence autour duquel le MAD peut fluctuer dans la bande.", shortEn: "Reference rate around which the MAD may fluctuate in the band.", longFr: "Le cours central du MAD est fixé par BAM en fonction du panier USD/EUR. Il est ajusté périodiquement (en général 1-2 fois par an) en fonction des fondamentaux (inflation différentielle, solde courant, réserves). Le MAD peut fluctuer ±2.5% autour.", longEn: "The MAD central rate is set by BAM based on the USD/EUR basket. It is adjusted periodically (typically 1-2 times per year) based on fundamentals (differential inflation, current account, reserves). The MAD may fluctuate ±2.5% around it.", category: 'monetary-policy', related: ["panier-de-reference","bande-de-fluctuation"], examples: [] },
  { slug: 'bande-de-fluctuation', term: "Bande de fluctuation ±2.5%", shortFr: "Marge autorisée du MAD autour du cours central depuis 2018.", shortEn: "Allowed MAD margin around the central rate since 2018.", longFr: "La bande de fluctuation officielle du MAD est de ±2.5% autour du cours central depuis janvier 2018. Avant, le régime était plus rigide. La bande permet une absorption graduelle des chocs externes sans dévaluation brutale.", longEn: "The official MAD fluctuation band is ±2.5% around the central rate since January 2018. Before, the regime was more rigid. The band allows gradual absorption of external shocks without brutal devaluation.", category: 'monetary-policy', related: ["cours-central","panier-de-reference"], examples: [] },
  { slug: 'intervention-bam', term: "Intervention BAM", shortFr: "Achat/vente de devises par BAM pour maintenir la bande.", shortEn: "BAM FX purchase/sale to maintain the band.", longFr: "Bank Al-Maghrib intervient sur le marché des changes pour maintenir le MAD dans la bande ±2.5%. Les interventions ne sont pas annoncées publiquement mais sont observables via les variations des réserves de change (qui passent de 360 à 320+ Mds MAD).", longEn: "Bank Al-Maghrib intervenes on the FX market to keep the MAD within the ±2.5% band. Interventions are not publicly announced but are observable via reserve changes (which range from 360 to 320+ Bn MAD).", category: 'monetary-policy', related: ["bam","reserves-de-change"], examples: [] },
  { slug: 'reserves-de-change', term: "Réserves de change BAM", shortFr: "Réserves en devises de BAM (~360 Mds MAD, ~5 mois d'imports).", shortEn: "BAM FX reserves (~360 Bn MAD, ~5 months of imports).", longFr: "Les réserves de change de BAM représentent ~360 Mds MAD (Q1 2025), couvrant ~5 mois d'importations. Elles constituent le bouclier principal contre les chocs externes (hausse taux Fed, crise tourisme, sécheresse). Un plancher implicite est ~3.5 mois d'imports.", longEn: "BAM FX reserves represent ~360 Bn MAD (Q1 2025), covering ~5 months of imports. They are the main shield against external shocks (Fed rate hikes, tourism crisis, drought). An implicit floor is ~3.5 months of imports.", category: 'monetary-policy', related: ["bam","intervention-bam"], examples: [] },
  { slug: 'couvertures-naturelles', term: "Couvertures naturelles", shortFr: "Élimination du risque de change par appariement flux même devise.", shortEn: "FX risk elimination by matching flows in same currency.", longFr: "Une couverture naturelle consiste à faire correspondre les recettes et dépenses dans la même devise (ex: exporter en USD et importer en USD). Elle élimine le risque de change sans coût d'instrument financier. Souvent la première étape d'une politique de couverture.", longEn: "A natural hedge is to match revenues and expenses in the same currency (e.g. export in USD and import in USD). It eliminates FX risk without financial instrument cost. Often the first step of a hedging policy.", category: 'risk-management', related: ["hedging","couverture-comptable"], examples: [] },
  { slug: 'risque-transaction', term: "Risque de transaction", shortFr: "Risque FX sur flux commerciaux à recevoir/payer (court terme).", shortEn: "FX risk on commercial flows receivable/payable (short-term).", longFr: "Le risque de transaction est le risque de change sur les créances et dettes commerciales en devise. C'est un risque comptable à court terme (<12 mois), couvert par forwards, swaps ou options. L'impact P&L est direct.", longEn: "Transaction risk is the FX risk on commercial receivables and payables in foreign currency. It is a short-term accounting risk (<12 months), hedged by forwards, swaps, or options. The P&L impact is direct.", category: 'risk-management', related: ["risque-economique","forward"], examples: [] },
  { slug: 'risque-economique', term: "Risque économique", shortFr: "Risque FX sur flux futurs (>1 an) ou marges compétitivité.", shortEn: "FX risk on future flows (>1y) or competitive margins.", longFr: "Le risque économique (ou compétitif) est l'impact du change sur la valeur actuelle des flux futurs (>1 an) ou la compétitivité-prix face aux concurrents. Plus stratégique et structurel que le risque de transaction. Couvert par couverture naturelle ou stratégie long terme.", longEn: "Economic risk (or competitive risk) is the impact of FX on the present value of future flows (>1 year) or price-competitiveness vs competitors. More strategic and structural than transaction risk. Hedged by natural hedge or long-term strategy.", category: 'risk-management', related: ["risque-transaction","couvertures-naturelles"], examples: [] },
  { slug: 'risque-comptable', term: "Risque comptable (translation)", shortFr: "Risque FX sur consolidation des filiales étrangères.", shortEn: "FX risk on consolidation of foreign subsidiaries.", longFr: "Le risque de translation (ou comptable) résulte de la consolidation en devise de reporting des états financiers de filiales étrangères. Les écarts de conversion passent en capitaux propres (OCI). Norme IAS 21.", longEn: "Translation risk (or accounting risk) results from reporting-currency consolidation of foreign subsidiaries' financial statements. Translation differences go to equity (OCI). IAS 21 standard.", category: 'risk-management', related: ["ias-21","risque-transaction"], examples: [] },
  { slug: 'ias-21', term: "IAS 21", shortFr: "Norme IFRS sur les effets des variations des cours des devises.", shortEn: "IFRS standard on effects of changes in foreign exchange rates.", longFr: "IAS 21 (IFRS) prescrit le traitement comptable des opérations en devises et la conversion des états financiers en monnaie de présentation. Elle définit la devise fonctionnelle et impose la comptabilisation des écarts de change en résultat ou en OCI.", longEn: "IAS 21 (IFRS) prescribes accounting treatment of foreign currency operations and translation of financial statements to presentation currency. It defines functional currency and requires FX differences recognition in P&L or OCI.", category: 'regulation-oc', related: ["risque-comptable","ifrs"], examples: [] },
  { slug: 'ifrs-7', term: "IFRS 7", shortFr: "Norme IFRS sur la communication des risques financiers.", shortEn: "IFRS standard on financial risk disclosure.", longFr: "IFRS 7 (anciennement IAS 32) impose la divulgation des risques financiers, dont le risque de change. Les entités doivent publier leur exposition FX, leurs couvertures (instruments, maturités, sensibilité). Audit obligatoire.", longEn: "IFRS 7 (formerly IAS 32) requires disclosure of financial risks, including FX risk. Entities must publish their FX exposure, hedges (instruments, maturities, sensitivity). Mandatory audit.", category: 'regulation-oc', related: ["ifrs","risque-transaction"], examples: [] },
  { slug: 'ifrs-9', term: "IFRS 9", shortFr: "Norme IFRS sur la classification et couverture (effective depuis 2018).", shortEn: "IFRS standard on classification and hedge accounting (effective 2018).", longFr: "IFRS 9 a remplacé IAS 39 en 2018. Il impose la comptabilité de couverture (hedge accounting) sur la base de la substance économique. Une couverture efficace doit être documentée et efficace à 80-125% (test prospectif/rétrospectif).", longEn: "IFRS 9 replaced IAS 39 in 2018. It imposes hedge accounting based on economic substance. An effective hedge must be documented and effective at 80-125% (prospective/retrospective test).", category: 'regulation-oc', related: ["ias-21","hedge-accounting"], examples: [] },
  { slug: 'hedge-accounting', term: "Hedge accounting (comptabilité de couverture)", shortFr: "IFRS 9: alignement comptable sur stratégie de gestion des risques.", shortEn: "IFRS 9: accounting alignment with risk management strategy.", longFr: "La comptabilité de couverture (hedge accounting) permet de compenser en P&L/OCI les variations de juste valeur de l'instrument couvert et de l'instrument de couverture. Trois types: fair value hedge, cash flow hedge, net investment hedge. Documentation obligatoire.", longEn: "Hedge accounting allows offsetting in P&L/OCI fair value variations of hedged and hedging instruments. Three types: fair value hedge, cash flow hedge, net investment hedge. Mandatory documentation.", category: 'regulation-oc', related: ["ifrs-9","hedging"], examples: [] },
  { slug: 'fair-value-hedge', term: "Fair value hedge", shortFr: "Couverture de la juste valeur d'un actif/engagement.", shortEn: "Hedge of fair value of an asset/liability.", longFr: "Le fair value hedge couvre l'exposition aux variations de la juste valeur d'un actif/passif reconnu ou d'un engagement ferme. L'instrument dérivé est réévalué en P&L, compensant la variation de l'élément couvert.", longEn: "The fair value hedge covers exposure to fair value changes of a recognized asset/liability or firm commitment. The derivative is remeasured in P&L, offsetting the hedged item change.", category: 'regulation-oc', related: ["hedge-accounting","cash-flow-hedge"], examples: [] },
  { slug: 'cash-flow-hedge', term: "Cash flow hedge", shortFr: "Couverture des variations de flux de trésorerie futurs.", shortEn: "Hedge of future cash flow variations.", longFr: "Le cash flow hedge couvre l'exposition à la variabilité des flux de trésorerie futurs attribuable à un risque particulier. La partie efficace est en OCI, la partie inefficace en P&L. Exemple classique: couverture d'un export EUR futur contre risque EUR/USD.", longEn: "The cash flow hedge covers exposure to variability of future cash flows attributable to a particular risk. Effective portion in OCI, ineffective in P&L. Typical example: hedging future EUR export against EUR/USD risk.", category: 'regulation-oc', related: ["hedge-accounting","fair-value-hedge"], examples: [] },
  { slug: 'net-investment-hedge', term: "Net investment hedge", shortFr: "Couverture d'un investissement net dans une activité à l'étranger.", shortEn: "Hedge of net investment in a foreign operation.", longFr: "Le net investment hedge couvre le risque de change d'une entité sur son investissement dans une activité à l'étranger (filiale, succursale). La partie efficace de la couverture est comptabilisée en écarts de conversion (OCI).", longEn: "The net investment hedge covers the FX risk of an entity on its investment in a foreign operation (subsidiary, branch). The effective portion of the hedge is recognized in translation differences (OCI).", category: 'regulation-oc', related: ["hedge-accounting","ias-21"], examples: [] },
  { slug: 'put-option', term: "Put option (option de vente)", shortFr: "Droit de vendre une devise à un cours donné (protection à la baisse).", shortEn: "Right to sell a currency at a given rate (downside protection).", longFr: "Un put option FX donne le droit (non l'obligation) de vendre une devise à un strike donné à maturité. Coût: la prime. L'acheteur d'un put est protégé si la devise baisse, mais conserve le gain si elle monte. Profil asymétrique favorable aux exportateurs.", longEn: "A put option FX gives the right (not the obligation) to sell a currency at a given strike at maturity. Cost: the premium. Put buyer is protected if currency falls, but keeps the gain if it rises. Asymmetric profile favorable to exporters.", category: 'instruments', related: ["call-option","option-vanille"], examples: [] },
  { slug: 'call-option', term: "Call option (option d'achat)", shortFr: "Droit d'acheter une devise à un cours donné (protection à la hausse).", shortEn: "Right to buy a currency at a given rate (upside protection).", longFr: "Un call option FX donne le droit (non l'obligation) d'acheter une devise à un strike donné à maturité. Coût: la prime. L'acheteur d'un call est protégé si la devise monte, mais n'est pas pénalisé si elle baisse. Profil asymétrique favorable aux importateurs.", longEn: "A call option FX gives the right (not the obligation) to buy a currency at a given strike at maturity. Cost: the premium. Call buyer is protected if currency rises, not penalized if it falls. Asymmetric profile favorable to importers.", category: 'instruments', related: ["put-option","option-vanille"], examples: [] },
  { slug: 'option-vanille', term: "Option vanille (vanilla option)", shortFr: "Option standard, exerçable à maturité uniquement (européenne).", shortEn: "Standard option, exercisable at maturity only (European).", longFr: "L'option vanille est l'option standard, exerçable uniquement à maturité (style européen) ou à tout moment (style américain). Pas de barrière ni de caractéristique exotique. Pricing: Black-Scholes (1973).", longEn: "The vanilla option is the standard option, exercisable only at maturity (European style) or anytime (American style). No barrier or exotic feature. Pricing: Black-Scholes (1973).", category: 'instruments', related: ["put-option","call-option","option-exotique"], examples: [] },
  { slug: 'option-exotique', term: "Option exotique", shortFr: "Option à barrière, digitale, asiatique, ou lookback.", shortEn: "Barrier, digital, Asian, or lookback option.", longFr: "Les options exotiques ont des payoff non-linéaires ou des déclencheurs (barrières). Types: knock-out (KO, disparaît si barriere touchée), knock-in (KI, apparaît si barrière touchée), digital (paiement fixe si condition), asiatique (moyenne sur période), lookback (strike = extrême). Moins chères que vanilles mais risque de structure complexe.", longEn: "Exotic options have non-linear payoffs or triggers (barriers). Types: knock-out (KO, disappears if barrier hit), knock-in (KI, appears if barrier hit), digital (fixed payment if condition), Asian (average over period), lookback (strike = extreme). Cheaper than vanillas but complex structure risk.", category: 'instruments', related: ["option-vanille","knock-out"], examples: [] },
  { slug: 'knock-out', term: "Knock-out (KO)", shortFr: "Option qui disparaît si la parité touche la barrière.", shortEn: "Option that disappears if parity touches the barrier.", longFr: "Un knock-out est une option barrière qui devient sans valeur (knock-out) si le sous-jacent franchit la barrière pendant la vie de l'option. Moins cher qu'une vanille. Risque: la couverture disparaît au pire moment.", longEn: "A knock-out is a barrier option that becomes worthless (knock-out) if the underlying crosses the barrier during the option life. Cheaper than a vanilla. Risk: hedge disappears at the worst moment.", category: 'instruments', related: ["option-exotique","knock-in"], examples: [] },
  { slug: 'collar', term: "Collar (tunnel)", shortFr: "Achat de put + vente de call pour borner le range de change.", shortEn: "Buy put + sell call to bound the FX range.", longFr: "Le collar combine un achat de put (plancher) et une vente de call (plafond). Prime nette faible ou nulle. Le coût de la prime du put est compensé par la prime reçue pour le call. Compromis: renoncement au gain au-delà du plafond.", longEn: "The collar combines a put purchase (floor) and a call sale (ceiling). Net premium low or zero. Put premium cost is offset by call premium received. Trade-off: forgo gain above ceiling.", category: 'instruments', related: ["put-option","call-option","risk-reversal"], examples: [] },
  { slug: 'risk-reversal', term: "Risk reversal", shortFr: "Achat de call + vente de put (ou inverse) à strikes hors-marché.", shortEn: "Buy call + sell put (or reverse) at off-market strikes.", longFr: "Le risk reversal achète une option OTM (call ou put) et vend l'autre option OTM. La structure a une prime nulle ou quasi-nulle. Indique la direction de la couverture et la skew de volatilité.", longEn: "The risk reversal buys an OTM option (call or put) and sells the other OTM option. Structure has zero or near-zero premium. Indicates hedge direction and volatility skew.", category: 'instruments', related: ["collar","option-vanille"], examples: [] },
  { slug: 'forward-points', term: "Forward points (points de report/déport)", shortFr: "Écart forward-spot en pips, signe report (+) ou déport (-).", shortEn: "Forward-spot gap in pips, premium (+) or discount (-) sign.", longFr: "Les forward points sont l'écart entre le forward et le spot, exprimé en pips. Positifs: report (la devise est en report à terme, taux d'intérêt domestique > étranger). Négatifs: déport. Formule: points = spot × (rate_dom - rate_for) × days/360.", longEn: "Forward points are the gap between forward and spot, expressed in pips. Positive: premium (currency is at forward premium, domestic rate > foreign). Negative: discount. Formula: points = spot × (dom_rate - for_rate) × days/360.", category: 'fx-basics', related: ["forward","taux-direct"], examples: [] },
  { slug: 'taux-direct', term: "Taux en direct (outright)", shortFr: "Cours forward ferme pour livraison à une date future.", shortEn: "Firm forward rate for delivery at a future date.", longFr: "Le taux en direct (outright) est le cours forward ferme, calculé comme spot + forward points. C'est le taux auquel une transaction forward est exécutée. Dépend du différentiel de taux d'intérêt et de la parité des taux d'intérêt couverte (CIP).", longEn: "The outright rate is the firm forward rate, calculated as spot + forward points. It is the rate at which a forward transaction is executed. Depends on interest rate differential and Covered Interest Parity (CIP).", category: 'fx-basics', related: ["forward-points","cip"], examples: [] },
  { slug: 'cip', term: "CIP (Covered Interest Parity)", shortFr: "Parité des taux d'intérêt couverte: F = S × (1+r_d)/(1+r_f).", shortEn: "Covered Interest Parity: F = S × (1+r_d)/(1+r_f).", longFr: "La CIP est une condition d'absence d'arbitrage: le différentiel de taux entre deux pays doit être compensé exactement par le différentiel forward-spot. F = S × (1+r_d)/(1+r_f). Si F > S×(1+r_d)/(1+r_f), arbitrage possible. En pratique, petite déviation (CIP basis).", longEn: "CIP is a no-arbitrage condition: the rate differential between two countries must be exactly compensated by the forward-spot differential. F = S × (1+r_d)/(1+r_f). If F > S×(1+r_d)/(1+r_f), arbitrage possible. In practice, small deviation (CIP basis).", category: 'fx-basics', related: ["taux-direct","uip"], examples: [] },
  { slug: 'uip', term: "UIP (Uncovered Interest Parity)", shortFr: "Parité non couverte: E[S_t+1] = S_t × (1+r_d)/(1+r_f).", shortEn: "Uncovered parity: E[S_t+1] = S_t × (1+r_d)/(1+r_f).", longFr: "L'UIP stipule que le taux de change spot futur anticipé compense exactement le différentiel de taux. En pratique, UIP échoue systématiquement (forward bias): les devises à taux élevé tendent à s'apprécier au lieu de se déprécier.", longEn: "UIP states that the expected future spot rate exactly compensates the rate differential. In practice, UIP systematically fails (forward bias): high-yield currencies tend to appreciate rather than depreciate.", category: 'fx-basics', related: ["cip","forward-bias"], examples: [] },
  { slug: 'forward-bias', term: "Forward bias (anomalie)", shortFr: "Écart systématique entre forward réalisé et forward anticipé.", shortEn: "Systematic gap between realized and predicted forward.", longFr: "Le forward bias est l'écart systématique entre le forward réalisé (ex-post) et le forward anticipé par l'UIP. Le carry trade exploite cette anomalie: les devises à taux élevé s'apprécient en moyenne au lieu de se déprécier.", longEn: "The forward bias is the systematic gap between realized (ex-post) forward and UIP-implied forward. Carry trade exploits this anomaly: high-yield currencies appreciate on average rather than depreciate.", category: 'fx-basics', related: ["uip","carry-trade"], examples: [] },
  { slug: 'carry-trade', term: "Carry trade", shortFr: "Stratégie: emprunter devise faible taux, investir devise forte taux.", shortEn: "Strategy: borrow low-yield currency, invest high-yield currency.", longFr: "Le carry trade est une stratégie spéculative qui consiste à emprunter une devise à faible taux d'intérêt pour investir dans une devise à taux élevé. Le profit est le différentiel de taux, moins la dépréciation anticipée. Exposée au risque de retournement brutal (unwind).", longEn: "The carry trade is a speculative strategy of borrowing a low-interest currency to invest in a high-interest currency. Profit is the rate differential, minus anticipated depreciation. Exposed to sudden unwind risk.", category: 'instruments', related: ["uip","forward-bias"], examples: [] },
  { slug: 'volatilite-implicite', term: "Volatilité implicite", shortFr: "Volatilité forward-anticipée par le marché, extraite des prix d'options.", shortEn: "Forward-expected volatility extracted from option prices.", longFr: "La volatilité implicite est la volatilité anticipée par le marché, déduite des prix d'options (inversion de Black-Scholes). S'exprime en % annualisé. Une hausse de la vol implicite indique un stress ou un événement attendu. ATM, risk reversal et butterfly mesurent la skew.", longEn: "Implied volatility is the market-expected volatility, inferred from option prices (Black-Scholes inversion). Expressed in annualized %. Rise in implied vol indicates stress or expected event. ATM, risk reversal and butterfly measure skew.", category: 'instruments', related: ["volatilite-realisee","skew"], examples: [] },
  { slug: 'volatilite-realisee', term: "Volatilité réalisée", shortFr: "Volatilité historique observée sur une période passée.", shortEn: "Historical volatility observed over a past period.", longFr: "La volatilité réalisée est l'écart-type des rendements log sur une fenêtre historique (10j, 1m, 3m, 1an). Annualisée par √252 (journalier) ou √52 (hebdo). Compare à la vol implicite pour détecter du sous/sur-coût de la prime d'option.", longEn: "Realized volatility is the standard deviation of log returns over a historical window (10d, 1m, 3m, 1y). Annualized by √252 (daily) or √52 (weekly). Compare to implied vol to detect under/over-cost of option premium.", category: 'instruments', related: ["volatilite-implicite","var"], examples: [] },
  { slug: 'var', term: "Value-at-Risk (VaR)", shortFr: "Perte maximale sur un horizon donné à un niveau de confiance.", shortEn: "Maximum loss over a given horizon at a confidence level.", longFr: "La Value-at-Risk (VaR) est la perte maximale estimée sur un horizon (1j, 10j) à un niveau de confiance (95%, 99%). Méthodes: historique, variance-covariance, Monte Carlo. Utile pour le reporting ALM et le calcul des RAR (actifs pondérés).", longEn: "Value-at-Risk (VaR) is the maximum estimated loss over a horizon (1d, 10d) at a confidence level (95%, 99%). Methods: historical, variance-covariance, Monte Carlo. Useful for ALM reporting and RWA (risk-weighted assets) calculation.", category: 'risk-management', related: ["expected-shortfall","stress-test"], examples: [] },
  { slug: 'expected-shortfall', term: "Expected Shortfall (ES)", shortFr: "Perte moyenne au-delà de la VaR (mesure cohérente du risque).", shortEn: "Average loss beyond VaR (coherent risk measure).", longFr: "L'Expected Shortfall (ES, ou CVaR) est la perte moyenne conditionnelle au-delà de la VaR. Plus conservative et cohérente que la VaR. Devenue la mesure standard post-Crisis (Bâle III/IV, FRTB). Niveau de confiance 97.5% typiquement.", longEn: "Expected Shortfall (ES, or CVaR) is the conditional average loss beyond VaR. More conservative and coherent than VaR. Became standard post-Crisis (Basel III/IV, FRTB). Confidence level 97.5% typically.", category: 'risk-management', related: ["var","stress-test"], examples: [] },
  { slug: 'stress-test', term: "Stress test FX", shortFr: "Scénarios extrêmes: -30% MAD, +200bps Fed, choc pétrole.", shortEn: "Extreme scenarios: -30% MAD, +200bps Fed, oil shock.", longFr: "Le stress test FX applique des scénarios extrêmes (historiques ou hypothétiques) pour mesurer l'impact sur le P&L, la liquidité ou la solvabilité. Exemples: -30% MAD/USD, +200bps Fed, pétrole à $150. Obligatoire pour le ICAAP/ILAAP bancaire.", longEn: "FX stress test applies extreme scenarios (historical or hypothetical) to measure P&L, liquidity or solvency impact. Examples: -30% MAD/USD, +200bps Fed, oil at $150. Mandatory for bank ICAAP/ILAAP.", category: 'risk-management', related: ["var","expected-shortfall"], examples: [] },
  { slug: 'frtb', term: "FRTB (Fundamental Review of Trading Book)", shortFr: "Nouvelle réglementation Bâle sur le risque de marché.", shortEn: "New Basel regulation on market risk.", longFr: "Le FRTB (Bâle III.5/IV) remplace les modèles VaR internes par des approches standardisées (SBM, DRC) ou internes (IMA). Impact majeur sur le capital de marché des banques. Expected Shortfall devient la mesure standard.", longEn: "FRTB (Basel III.5/IV) replaces internal VaR models with standardized (SBM, DRC) or internal (IMA) approaches. Major impact on banks' market capital. Expected Shortfall becomes the standard measure.", category: 'regulation-oc', related: ["expected-shortfall","bale-iv"], examples: [] },
  { slug: 'bale-iv', term: "Bâle IV", shortFr: "Réforme 2025-2030 du ratio de solvabilité bancaire.", shortEn: "2025-2030 banking solvency ratio reform.", longFr: "Bâle IV (finalisé 2017, mise en œuvre progressive 2025-2030) renforce les exigences de fonds propres, durcit les modèles internes (output floor 72.5%), intègre le risque opérationnel (SA-OR), le risque de marché (FRTB) et le risque CVA.", longEn: "Basel IV (finalized 2017, progressive 2025-2030) strengthens capital requirements, tightens internal models (72.5% output floor), integrates operational risk (SA-OR), market risk (FRTB) and CVA risk.", category: 'regulation-oc', related: ["frtb","ratio-solvabilite"], examples: [] },
  { slug: 'ratio-solvabilite', term: "Ratio de solvabilité CET1", shortFr: "Fonds propres durs / actifs pondérés (min Bâle: 4.5% + buffers).", shortEn: "Tier 1 capital / risk-weighted assets (min Basel: 4.5% + buffers).", longFr: "Le ratio CET1 (Common Equity Tier 1) mesure la solvabilité bancaire: fonds propres durs (capital social + réserves) divisés par les actifs pondérés (RWA). Minimum Bâle: 4.5% + buffers (conservation 2.5%, contracyclique 0-2.5%, SIB 1-3.5%).", longEn: "The CET1 (Common Equity Tier 1) ratio measures bank solvency: tier 1 capital (equity + reserves) divided by risk-weighted assets (RWA). Basel minimum: 4.5% + buffers (conservation 2.5%, countercyclical 0-2.5%, SIB 1-3.5%).", category: 'regulation-oc', related: ["bale-iv","rar"], examples: [] },
  { slug: 'rar', term: "RWA (Risk-Weighted Assets)", shortFr: "Actifs pondérés par le risque: contreparties, marché, opérationnel.", shortEn: "Risk-weighted assets: counterparty, market, operational.", longFr: "Les RWA (Risk-Weighted Assets) sont les actifs du bilan pondérés par leur risque (counterparty, marché, opérationnel, CVA). Calculés selon les approches standard (look-up tables) ou internes (IRB). Déterminent le capital minimum requis.", longEn: "RWA (Risk-Weighted Assets) are balance sheet assets weighted by their risk (counterparty, market, operational, CVA). Calculated per standardized (look-up tables) or internal (IRB) approaches. Determine minimum required capital.", category: 'regulation-oc', related: ["ratio-solvabilite","cva"], examples: [] },
  { slug: 'cva', term: "CVA (Credit Valuation Adjustment)", shortFr: "Ajustement de valeur d'un dérivé pour le risque de crédit contrepartie.", shortEn: "Derivative value adjustment for counterparty credit risk.", longFr: "La CVA (Credit Valuation Adjustment) est la valeur de marché du risque de crédit de la contrepartie sur un dérivé OTC. Calculée par simulation Monte Carlo ou par formula (SA-CVA Bâle IV). Capitaux propres requis depuis Bâle III.", longEn: "CVA (Credit Valuation Adjustment) is the market value of counterparty credit risk on an OTC derivative. Computed by Monte Carlo simulation or formula (SA-CVA Basel IV). Capital required since Basel III.", category: 'regulation-oc', related: ["xva","rar"], examples: [] },
  { slug: 'xva', term: "XVA (X-Value Adjustments)", shortFr: "Ensemble des ajustements: CVA, DVA, FVA, MVA, KVA.", shortEn: "Set of adjustments: CVA, DVA, FVA, MVA, KVA.", longFr: "Les XVA regroupent les ajustements de valeur d'un dérivé au-delà du prix mid: CVA (crédit contrepartie), DVA (crédit propre), FVA (financement), MVA (marge), KVA (capital). Impact P&L significatif pour les desks de dérivés OTC.", longEn: "XVAs group derivative value adjustments beyond the mid price: CVA (counterparty credit), DVA (own credit), FVA (funding), MVA (margin), KVA (capital). Significant P&L impact for OTC derivative desks.", category: 'regulation-oc', related: ["cva","dva"], examples: [] },
  { slug: 'dva', term: "DVA (Debit Valuation Adjustment)", shortFr: "Ajustement pour risque de crédit propre sur passif dérivé.", shortEn: "Adjustment for own credit risk on derivative liability.", longFr: "La DVA est l'ajustement symétrique à la CVA: elle reflète la valeur de marché du risque de crédit propre de l'entité sur ses passifs dérivés. Impact P&L négatif en cas de dégradation de la notation propre.", longEn: "DVA is the symmetric adjustment to CVA: it reflects the market value of own credit risk on derivative liabilities. Negative P&L impact in case of own rating downgrade.", category: 'regulation-oc', related: ["cva","xva"], examples: [] },
  { slug: 'fva', term: "FVA (Funding Valuation Adjustment)", shortFr: "Ajustement pour coût de financement des dérivés non collatéralisés.", shortEn: "Adjustment for funding cost of uncollateralized derivatives.", longFr: "La FVA capture le coût de financement des expositions non collatéralisées (FBA, FVA decomposition). Souvent le XVA le plus important pour les banques. Non réglementaire mais économiquement significatif.", longEn: "FVA captures funding cost of uncollateralized exposures (FBA, FVA decomposition). Often the most important XVA for banks. Non-regulatory but economically significant.", category: 'regulation-oc', related: ["xva","cva"], examples: [] },

  { slug: 'fixing-bkam', term: "Fixing BKAM", shortFr: "Cours de référence quotidien publié par BAM à 12h30.", shortEn: "Daily reference rate published by BAM at 12:30.", longFr: "Le fixing BKAM est le cours de change de référence publié chaque jour ouvrable par Bank Al-Maghrib à 12h30. Cours virement (transfert) + cours billet (cash). Utilisé pour la facturation, les déclarations douanières, et les opérations de change.", longEn: "The BKAM fixing is the reference exchange rate published every business day by Bank Al-Maghrib at 12:30. Transfer rate (wire) + banknote rate (cash). Used for invoicing, customs declarations, and FX operations.", category: 'fx-basics', related: ["bam","bkam-rates"], examples: [] },
  { slug: 'bkam-rates', term: "Cours BKAM", shortFr: "Taux de change officiels publiés chaque jour par BAM.", shortEn: "Official daily exchange rates published by BAM.", longFr: "Les cours BKAM sont les taux de change officiels du dirham face à ~30 devises. Publiés chaque jour ouvrable. Incluent: cours virement (transferts interbancaires) + cours billet (cash) + cross-rates. Source: bkam.ma.", longEn: "BKAM rates are the official dirham exchange rates against ~30 currencies. Published every business day. Include: transfer rates (interbank wires) + banknote rates (cash) + cross-rates. Source: bkam.ma.", category: 'fx-basics', related: ["fixing-bkam"], examples: [] },
  { slug: 'cls-bank', term: "CLS Bank", shortFr: "Continuous Linked Settlement, système de paiement FX PvP.", shortEn: "Continuous Linked Settlement, PvP FX payment system.", longFr: "CLS Bank est le système de règlement FX multilatéral exploité par CLS Bank International. Règle les transactions FX en mode PvP (Payment-versus-Payment), éliminant le risque Herstatt. 18 devises éligibles. ~50% du volume FX mondial.", longEn: "CLS Bank is the multilateral FX settlement system operated by CLS Bank International. Settles FX transactions in PvP (Payment-versus-Payment) mode, eliminating Herstatt risk. 18 eligible currencies. ~50% of global FX volume.", category: 'fx-basics', related: ["value-date","herstatt"], examples: [] },
  { slug: 'herstatt', term: "Risque Herstatt", shortFr: "Risque de règlement dune seule jambe dun swap FX.", shortEn: "Risk of one leg settlement only in an FX swap.", longFr: "Le risque Herstatt est le risque de perdre une jambe dun swap FX sans recevoir la contrepartie. Doit son nom à la faillite de Bankhaus Herstatt en 1974. Éliminé par CLS Bank pour les paires éligibles. Reste pour les devises non-CLS (MAD).", longEn: "Herstatt risk is the risk of losing one leg of an FX swap without receiving the counterparty. Named after the 1974 Bankhaus Herstatt failure. Eliminated by CLS Bank for eligible pairs. Remains for non-CLS currencies (MAD).", category: 'risk-management', related: ["cls-bank"], examples: [] },
  { slug: 'csa', term: "CSA (Credit Support Annex)", shortFr: "Annexe de support de crédit pour dérivés OTC.", shortEn: "Credit support annex for OTC derivatives.", longFr: "Le CSA est l'annexe au contrat-cadre ISDA qui définit les conditions de remise de collatéral. Réduit le risque de crédit de contrepartie sur les dérivés OTC. Réglementé par EMIR (UE) et Dodd-Frank (US).", longEn: "CSA is the annex to the ISDA master agreement that defines collateral posting conditions. Reduces counterparty credit risk on OTC derivatives. Regulated by EMIR (EU) and Dodd-Frank (US).", category: 'risk-management', related: ["emir","isda"], examples: [] },
  { slug: 'isda', term: "ISDA Master Agreement", shortFr: "Contrat-cadre international pour dérivés OTC.", shortEn: "International master agreement for OTC derivatives.", longFr: "L'ISDA Master Agreement est le contrat-cadre standard international pour les dérivés OTC. Définit les conditions de négociation, les événements de défaut, les mécanismes de close-out. Standard depuis 1985. Version 2002 inclut l'annexe CSA.", longEn: "The ISDA Master Agreement is the standard international master agreement for OTC derivatives. Defines trading conditions, events of default, close-out mechanisms. Standard since 1985. 2002 version includes the CSA annex.", category: 'instruments', related: ["csa","dodd-frank"], examples: [] },
  { slug: 'emir', term: "EMIR (European Market Infrastructure Regulation)", shortFr: "Règlement européen sur les dérivés OTC.", shortEn: "European regulation on OTC derivatives.", longFr: "EMIR est le règlement européen de 2012 sur les dérivés OTC. Impose la déclaration des transactions aux trade repositories, le clearing central pour les dérivés standardisés, et le collateral pour les bilatéraux. Réplique par Dodd-Frank aux US.", longEn: "EMIR is the 2012 European regulation on OTC derivatives. Requires transaction reporting to trade repositories, central clearing for standardized derivatives, and collateral for bilateral. Replicated by Dodd-Frank in the US.", category: 'regulation-oc', related: ["dodd-frank","csa"], examples: [] },
  { slug: 'dodd-frank', term: "Dodd-Frank Act", shortFr: "Réglementation US post-2008, dérivés et banques.", shortEn: "US post-2008 regulation, derivatives and banks.", longFr: "Le Dodd-Frank Wall Street Reform Act (2010) est la réponse américaine à la crise de 2008. Impose la compensation centrale pour les dérivés standardisés, la conservation par CCP, la transparence des marchés de swap, et le Volcker Rule (interdiction du prop trading pour les banques).", longEn: "Dodd-Frank is the 2010 American response to the 2008 crisis. Requires central clearing for standardized derivatives, CCP custody, swap market transparency, and the Volcker Rule (ban on prop trading for banks).", category: 'regulation-oc', related: ["emir","volcker-rule"], examples: [] },
  { slug: 'volcker-rule', term: "Volcker Rule", shortFr: "Interdiction du prop trading pour les banques US.", shortEn: "Ban on prop trading for US banks.", longFr: "La Volcker Rule (Section 619 Dodd-Frank) interdit aux banques de dépôts US de faire du trading pour compte propre. Exemptions: market making, hedging, certaines activités dinvestissement. Renforcée en 2020 par la Fed.", longEn: "The Volcker Rule prohibits US depository banks from proprietary trading. Exemptions: market making, hedging, certain investment activities. Strengthened in 2020 by the Fed.", category: 'regulation-oc', related: ["dodd-frank"], examples: [] },
  { slug: 'ccp', term: "CCP (Central Counterparty)", shortFr: "Contrepartie centrale pour le clearing des dérivés.", shortEn: "Central counterparty for derivatives clearing.", longFr: "Une CCP est une chambre de compensation qui sinterpose entre les contreparties dune transaction. Devient acheteur pour le vendeur et vendeur pour lacheteur. Réduit le risque de contrepartie. Principales: LCH (Londres), CME (Chicago), Eurex (Francfort).", longEn: "A CCP is a clearing house that interposes between the counterparties of a transaction. Becomes buyer for the seller and seller for the buyer. Reduces counterparty risk. Main: LCH (London), CME (Chicago), Eurex (Frankfurt).", category: 'instruments', related: ["emir","dodd-frank"], examples: [] },
  { slug: 'esma', term: "ESMA (European Securities and Markets Authority)", shortFr: "Régulateur européen des marchés de titres.", shortEn: "European securities markets regulator.", longFr: "L'ESMA est lautorité européenne des marchés financiers. Basée à Paris. Émet des standards techniques (RTS/ITS) et coordonne les régulateurs nationaux (AMF, BaFin, Consob). Rôle clé dans EMIR, MIFIR, et la régulation crypto.", longEn: "ESMA is the European Securities and Markets Authority. Based in Paris. Issues technical standards (RTS/ITS) and coordinates national regulators. Key role in EMIR, MIFIR, and crypto regulation.", category: 'regulation-oc', related: ["emir","amf"], examples: [] },
  { slug: 'bce-taux', term: "Taux BCE", shortFr: "Taux de dépôt BCE, taux directeur zone euro.", shortEn: "ECB deposit rate, euro area policy rate.", longFr: "Le taux de dépôt BCE est le taux directeur de la zone euro. Niveau 2026: ~2.50%. Influence majeure sur EUR/USD et donc sur le panier BAM (40% EUR).", longEn: "The ECB Deposit Facility Rate is the euro area policy rate. 2026 level: ~2.50%. Major influence on EUR/USD and thus on the BAM basket (40% EUR).", category: 'monetary-policy', related: ["bce","eur-usd"], examples: [] },
  { slug: 'bce', term: "BCE", shortFr: "Banque Centrale Européenne, BCE Frankfurt.", shortEn: "European Central Bank, ECB Frankfurt.", longFr: "La BCE conduit la politique monétaire unique pour les 20 pays de la zone euro. Elle fixe les taux directeurs (refi, deposit, lending) et gère le programme dasset purchases (PEPP, APP).", longEn: "The ECB conducts single monetary policy for the 20 euro area countries. It sets policy rates (refi, deposit, lending) and manages asset purchase programs (PEPP, APP).", category: 'monetary-policy', related: ["bce-taux","eur-usd"], examples: [] },
  { slug: 'eur-usd', term: "EUR/USD", shortFr: "Paire la plus liquide du monde, EUR contre USD.", shortEn: "Most liquid pair globally, EUR vs USD.", longFr: "La paire EUR/USD est la plus échangée au monde (volume quotidien ~7.5 trillions USD en 2025). Influence directe sur le panier BAM (60% USD, 40% EUR).", longEn: "EUR/USD is the most traded pair globally (daily volume ~$7.5 trillion in 2025). Direct influence on the BAM basket (60% USD, 40% EUR).", category: 'fx-basics', related: ["taux-de-change","cip"], examples: [] },
  { slug: 'dxy', term: "DXY (Dollar Index)", shortFr: "Indice du dollar US face à un panier de 6 devises.", shortEn: "US Dollar Index against a basket of 6 currencies.", longFr: "Le DXY mesure la valeur du dollar face à un panier de 6 devises: EUR (57.6%), JPY (13.6%), GBP (11.9%), CAD (9.1%), SEK (4.2%), CHF (3.6%). Niveau 2026: ~104. Une hausse du DXY déprécie mécaniquement le MAD.", longEn: "The DXY measures the dollar value against a basket of 6 currencies. 2026 level: ~104. A DXY rise mechanically depreciates the MAD.", category: 'fx-basics', related: ["usd-mad","eur-usd"], examples: [] },
  { slug: 'fed-rate', term: "Taux Fed", shortFr: "Taux directeur Federal Reserve (Fed Funds Rate).", shortEn: "Federal Reserve policy rate (Fed Funds Rate).", longFr: "Le taux Fed Funds est la cible de la Federal Reserve pour le taux au jour le jour. Influence majeure sur USD et donc sur le panier BAM (60% USD). Niveau 2026: ~4.25-4.50%.", longEn: "The Fed Funds Rate is the Federal Reserve target for the overnight rate. 2026 level: ~4.25-4.50%.", category: 'monetary-policy', related: ["taux-directeur","ust-10y"], examples: [] },
  { slug: 'ust-10y', term: "UST 10 ans", shortFr: "US Treasury 10 ans, taux sans risque USD.", shortEn: "US Treasury 10-year, USD risk-free rate.", longFr: "Le UST 10 ans est le taux sans risque de référence USD. Taux 2026: ~4.40%. Utilisé pour le pricing de toutes les options USD, le calcul des forward points, et la valorisation des flux USD futurs.", longEn: "The 10-year US Treasury is the USD risk-free rate. 2026 rate: ~4.40%. Used for pricing all USD options, calculating forward points, and valuing future USD flows.", category: 'instruments', related: ["fed-rate","oat-10y"], examples: [] },
  { slug: 'bdt-13w', term: "BDT 13 semaines", shortFr: "Bons du Trésor à 13 semaines, adjudication hebdomadaire.", shortEn: "13-week Treasury Bills, weekly auction.", longFr: "Les BDT 13 semaines sont linstrument de référence de la politique monétaire court terme. Adjudiqués chaque mardi par BAM, ils servent de référence pour le calcul des forward points MAD et la tarification des swaps.", longEn: "13-week T-Bills are the reference instrument for short-term monetary policy. Auctioned every Tuesday by BAM.", category: 'instruments', related: ["bdt","taux-directeur"], examples: [] },
  { slug: 'monia', term: "MONIA", shortFr: "Moroccan Overnight Index Average, taux interbancaire au jour le jour.", shortEn: "Moroccan Overnight Index Average, overnight interbank rate.", longFr: "Le MONIA est le taux de référence du marché interbancaire MAD au jour le jour. Calculé par BAM à partir des transactions déclarées par les banques.", longEn: "MONIA is the MAD overnight interbank reference rate. Computed by BAM from bank transactions.", category: 'instruments', related: ["bdt","taux-directeur"], examples: [] },
  { slug: 'taux-directeur', term: "Taux directeur BAM", shortFr: "Taux de référence des appels doffres BAM, actuellement 2.75%.", shortEn: "BAM reference rate, currently 2.75%.", longFr: "Le taux directeur de BAM est le taux des appels doffres à 7 jours. Il sert de référence pour le marché monétaire (BDT, MONIA) et influence les conditions bancaires.", longEn: "The BAM policy rate is the 7-day repo rate. 2026 level: 2.75%.", category: 'monetary-policy', related: ["bdt","monia"], examples: [] },
  { slug: 'oat-10y', term: "OAT 10 ans", shortFr: "Obligation Assimilable du Trésor à 10 ans, taux souverain MAD.", shortEn: "10-year Treasury bond, MAD sovereign rate.", longFr: "Les OAT 10 ans sont linstrument de référence de la courbe souveraine MAD. Taux 2026: ~3.40%. Utilisé pour le pricing des CCS, et lévaluation de la prime de risque souverain.", longEn: "10-year OATs are the reference for the MAD sovereign curve. 2026 rate: ~3.40%.", category: 'instruments', related: ["bdt","oat-5y"], examples: [] },
  { slug: 'bam', term: "BAM (Bank Al-Maghrib)", shortFr: "Banque centrale du Maroc, fondée 1959.", shortEn: "Morocco central bank, founded 1959.", longFr: "Bank Al-Maghrib est la banque centrale du Royaume du Maroc. Émet le dirham, conduit la politique monétaire, supervise le système bancaire, gère les réserves de change. Siège à Rabat.", longEn: "Bank Al-Maghrib is the central bank of Morocco. Issues the dirham, conducts monetary policy, supervises the banking system, manages FX reserves.", category: 'monetary-policy', related: ["taux-directeur","fixing-bkam"], examples: [] },
  { slug: 'oc', term: "Office des Changes", shortFr: "Office des Changes du Maroc, régulateur du change.", shortEn: "Office des Changes of Morocco, FX regulator.", longFr: "LOffice des Changes (OC) est lorganisme public chargé de la réglementation et du contrôle des opérations de change au Maroc. Émet les circulaires (notamment 01/2024) et les instructions.", longEn: "The Office des Changes (OC) is the public body in charge of FX regulation and control in Morocco. Issues circulars (notably 01/2024) and instructions.", category: 'regulation-oc', related: ["circ-oc-01-2024","bam"], examples: [] },
  { slug: 'circ-oc-01-2024', term: "Circ. OC 01/2024", shortFr: "Reporting mensuel PME >500K MAD, déclaration IGOC.", shortEn: "Monthly SME reporting >500K MAD, IGOC declaration.", longFr: "La circulaire OC 01/2024 impose aux PME importatrices/exportatrices dont le CA mensuel dépasse 500 000 MAD un reporting mensuel détaillé via IGOC. Sanction: 5% par mois de retard, plafonné 50%.", longEn: "Circ. OC 01/2024 requires importing/exporting SMEs with monthly turnover >500,000 MAD to file detailed monthly reporting via IGOC. Penalty: 5% per month of delay, capped 50%.", category: 'regulation-oc', related: ["reporting-pme","igoc"], examples: [] },
  { slug: 'cde', term: "CDE (Compte en Devises Étrangères)", shortFr: "Compte bancaire en devises pour particuliers résidents.", shortEn: "Foreign currency bank account for resident individuals.", longFr: "Le CDE permet à toute personne physique résidente de détenir jusquà 100% de ses revenus en devises. Plafond annuel: 200 000 MAD dalimentation par an. Intérêts crédités en devises.", longEn: "CDE allows any resident individual to hold up to 100% of their income in foreign currency. Annual ceiling: 200,000 MAD.", category: 'regulation-oc', related: ["cpec","cdecpec-2015"], examples: [] },
  { slug: 'cpec', term: "CPEC (Compte Professionnel en Devises)", shortFr: "Compte professionnel en devises pour exportateurs.", shortEn: "Professional foreign currency account for exporters.", longFr: "Le CPEC est réservé aux exportateurs (CA export > 5M MAD/an). Permet de conserver 70% des recettes dexportation en devises. Utilisation: importations, frais à létranger, investissements productifs.", longEn: "CPEC is reserved for exporters (export revenue > 5M MAD/year). Allows keeping 70% of export proceeds in foreign currency.", category: 'regulation-oc', related: ["cde","cdecpec-2015"], examples: [] },
  { slug: 'igoc', term: "IGOC 2024", shortFr: "Interface de Gestion des Opérations de Change, BAM.", shortEn: "Interface for FX Operations Management, BAM.", longFr: "LIGOC 2024 est le portail de télédéclaration de BAM. Remplace SID. Inclut la déclaration en temps réel des opérations > 200 000 MAD, le reporting PME mensuel, la gestion CDE/CPEC, et les attestations de rapatriement.", longEn: "IGOC 2024 is BAM teledeclaration portal. Replaces SID. Includes real-time declaration of operations > 200,000 MAD, monthly SME reporting, CDE/CPEC management.", category: 'regulation-oc', related: ["circ-oc-01-2024"], examples: [] },
  { slug: 'convertibilite', term: "Convertibilité du MAD", shortFr: "Liberté de conversion du dirham en devises étrangères.", shortEn: "Freedom of conversion of dirham to foreign currency.", longFr: "Le MAD est convertible en compte courant depuis 1993 et en compte capital depuis janvier 2018 (Phase II). Phase III attendue en 2029-2030. Restrictions résiduelles: plafond CDE, IDE sortant.", longEn: "MAD is convertible in current account since 1993 and in capital account since January 2018 (Phase II). Phase III expected 2029-2030.", category: 'regulation-oc', related: ["phase-iii"], examples: [] },
  { slug: 'cros', term: "Cross-currency Swap (CCS)", shortFr: "Swap de change + swap de taux, échange de principal.", shortEn: "FX swap + rate swap, principal exchange.", longFr: "Le CCS (Cross-Currency Swap) combine un swap de taux et un swap de change. Échange de principal initial et final, plus échanges de coupons périodiques. Maturités 2-30 ans typiques.", longEn: "CCS combines an interest rate swap and an FX swap. Initial and final principal exchange, plus periodic coupon exchanges. Maturities 2-30 years typical.", category: 'instruments', related: ["swap","xcs"], examples: [] },
  { slug: 'xcs', term: "Cross-currency basis (XCS)", shortFr: "Écart entre XCS observé et CIP théorique.", shortEn: "Gap between observed and theoretical CIP XCS.", longFr: "Le XCS basis mesure lécart entre le taux de swap cross-currency observé et la prédiction théorique par CIP. 2024-2026: 5-15 bps sur EUR/MAD.", longEn: "XCS basis measures the gap between observed cross-currency swap rate and theoretical CIP prediction. 2024-2026: 5-15 bps on EUR/MAD.", category: 'instruments', related: ["cip","cross-currency-swap"], examples: [] },
  { slug: 'cip', term: "CIP (Covered Interest Parity)", shortFr: "Parité des taux dintérêt couverte.", shortEn: "Covered Interest Parity.", longFr: "La CIP est une condition dabsence darbitrage: le différentiel de taux entre deux pays doit être compensé exactement par le différentiel forward-spot. F = S × (1+r_d)/(1+r_f).", longEn: "CIP is a no-arbitrage condition: the rate differential between two countries must be exactly compensated by the forward-spot differential.", category: 'fx-basics', related: ["taux-direct","uip"], examples: [] },
  { slug: 'uip', term: "UIP (Uncovered Interest Parity)", shortFr: "Parité non couverte: E[S_t+1] = S_t × (1+r_d)/(1+r_f).", shortEn: "Uncovered parity.", longFr: "LUIP stipule que le taux de change spot futur anticipé compense exactement le différentiel de taux. En pratique, UIP échoue systématiquement (forward bias).", longEn: "UIP states that the expected future spot rate exactly compensates the rate differential. In practice, UIP systematically fails (forward bias).", category: 'fx-basics', related: ["cip","forward-bias"], examples: [] },
  { slug: 'volatilite-implicite', term: "Volatilité implicite", shortFr: "Volatilité forward-anticipée, extraite des prix doptions.", shortEn: "Forward-expected volatility extracted from option prices.", longFr: "La volatilité implicite est la volatilité anticipée par le marché, déduite des prix doptions (inversion de Black-Scholes). Sexprime en % annualisé.", longEn: "Implied volatility is the market-expected volatility, inferred from option prices (Black-Scholes inversion).", category: 'instruments', related: ["volatilite-realisee","skew"], examples: [] },
  { slug: 'var', term: "Value-at-Risk (VaR)", shortFr: "Perte maximale sur un horizon donné à un niveau de confiance.", shortEn: "Maximum loss over a given horizon at a confidence level.", longFr: "La Value-at-Risk est la perte maximale estimée sur un horizon (1j, 10j) à un niveau de confiance (95%, 99%). Méthodes: historique, variance-covariance, Monte Carlo.", longEn: "Value-at-Risk is the maximum estimated loss over a horizon at a confidence level. Methods: historical, variance-covariance, Monte Carlo.", category: 'risk-management', related: ["expected-shortfall","stress-test"], examples: [] },
  { slug: 'expected-shortfall', term: "Expected Shortfall (ES)", shortFr: "Perte moyenne au-delà de la VaR.", shortEn: "Average loss beyond VaR.", longFr: "LExpected Shortfall (ES, ou CVaR) est la perte moyenne conditionnelle au-delà de la VaR. Plus conservative et cohérente que la VaR. Niveau de confiance 97.5% typiquement.", longEn: "Expected Shortfall is the conditional average loss beyond VaR. More conservative and coherent than VaR.", category: 'risk-management', related: ["var","stress-test"], examples: [] },
  { slug: 'xva', term: "XVA (X-Value Adjustments)", shortFr: "Ensemble des ajustements: CVA, DVA, FVA, MVA, KVA.", shortEn: "Set of adjustments: CVA, DVA, FVA, MVA, KVA.", longFr: "Les XVA regroupent les ajustements de valeur dun dérivé au-delà du prix mid. Impact P&L significatif pour les desks de dérivés OTC.", longEn: "XVAs group derivative value adjustments beyond the mid price. Significant P&L impact for OTC derivative desks.", category: 'regulation-oc', related: ["cva","dva"], examples: [] },
  { slug: 'ifrs-9', term: "IFRS 9", shortFr: "Norme IFRS sur la classification et couverture (effective depuis 2018).", shortEn: "IFRS standard on classification and hedge accounting.", longFr: "IFRS 9 a remplacé IAS 39 en 2018. Il impose la comptabilité de couverture sur la base de la substance économique.", longEn: "IFRS 9 replaced IAS 39 in 2018. It imposes hedge accounting based on economic substance.", category: 'regulation-oc', related: ["ias-21","hedge-accounting"], examples: [] },
  { slug: 'hedge-accounting', term: "Hedge accounting", shortFr: "IFRS 9: alignement comptable sur stratégie de gestion des risques.", shortEn: "IFRS 9: accounting alignment with risk management strategy.", longFr: "La comptabilité de couverture permet de compenser en P&L/OCI les variations de juste valeur de linstrument couvert et de linstrument de couverture.", longEn: "Hedge accounting allows offsetting fair value variations of hedged and hedging instruments.", category: 'regulation-oc', related: ["ifrs-9","hedging"], examples: [] },
  { slug: 'ratio-solvabilite', term: "Ratio de solvabilité CET1", shortFr: "Fonds propres durs / actifs pondérés (min Bâle: 4.5% + buffers).", shortEn: "Tier 1 capital / risk-weighted assets.", longFr: "Le ratio CET1 mesure la solvabilité bancaire: fonds propres durs divisés par les actifs pondérés. Minimum Bâle: 4.5% + buffers.", longEn: "The CET1 ratio measures bank solvency. Basel minimum: 4.5% + buffers.", category: 'regulation-oc', related: ["bale-iv","rar"], examples: [] },
  { slug: 'bale-iv', term: "Bâle IV", shortFr: "Réforme 2025-2030 du ratio de solvabilité bancaire.", shortEn: "2025-2030 banking solvency ratio reform.", longFr: "Bâle IV (finalisé 2017, mise en œuvre progressive 2025-2030) renforce les exigences de fonds propres, durcit les modèles internes (output floor 72.5%).", longEn: "Basel IV (2017, progressive 2025-2030) strengthens capital requirements, tightens internal models (72.5% output floor).", category: 'regulation-oc', related: ["frtb","ratio-solvabilite"], examples: [] },
  { slug: 'kva', term: "KVA (Capital Valuation Adjustment)", shortFr: "Ajustement pour coût du capital réglementaire.", shortEn: "Adjustment for regulatory capital cost.", longFr: "La KVA est lajustement de valeur dun dérivé pour tenir compte du coût du capital réglementaire (CET1) alloué à la transaction.", longEn: "KVA is the derivative value adjustment for the cost of the regulatory capital (CET1) allocated to the transaction.", category: 'regulation-oc', related: ["xva","cva"], examples: [] },
];
  return term.related.map(getTermBySlug).filter((t): t is GlossaryTerm => Boolean(t));
}

export function getTermsByCategory(category: GlossaryCategory): GlossaryTerm[] {
  return GLOSSARY.filter((t) => t.category === category);
}

export function searchTerms(query: string): GlossaryTerm[] {
  const q = query.toLowerCase().trim();
  if (!q) return GLOSSARY;
  return GLOSSARY.filter(
    (t) =>
      t.term.toLowerCase().includes(q) ||
      t.shortFr.toLowerCase().includes(q) ||
      t.shortEn.toLowerCase().includes(q) ||
      t.longFr.toLowerCase().includes(q),
  );
}
